const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">CAREER · CORE DEEP DIVE</div>\n  <div class=\"nav-title\">CS DB 보안 심화 면접</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>학습 로드맵</a>\n  <a href=\"#career-readiness-gate\"><span class=\"code\">GATE</span>답변 준비도</a>\n  <a href=\"#career-answer-rubric\"><span class=\"code\">RUBRIC</span>답변 품질</a>\n  <a href=\"#career-pressure-loop\"><span class=\"code\">LOOP</span>압박 대응</a>\n  <a href=\"#career-evidence-packet\"><span class=\"code\">EVIDENCE</span>증거 패킷</a>\n  <a href=\"#career-output-packet\"><span class=\"code\">OUTPUT</span>답변 산출물</a>\n  <a href=\"#career-final-drill\"><span class=\"code\">DRILL</span>최종 점검</a>\n  <a href=\"#doc-cs\"><span class=\"code\">DOC</span>CS 기본기 면접</a>\n  <a href=\"#doc-dbdeep\"><span class=\"code\">DOC</span>DB 심화 면접</a>\n  <a href=\"#doc-security\"><span class=\"code\">DOC</span>보안 심화 면접</a>\n  <a href=\"#doc-cs\"><span class=\"code\">PART</span>CS 기본기 면접</a>\n<a href=\"#cs-q1\"><span class=\"code\">CS-01</span>Big-O</a>\n  <a href=\"#cs-q2\"><span class=\"code\">CS-02</span>자료구조</a>\n  <a href=\"#cs-q3\"><span class=\"code\">CS-03</span>Hash collision</a>\n  <a href=\"#cs-q4\"><span class=\"code\">CS-04</span>BFS/DFS</a>\n  <a href=\"#cs-q5\"><span class=\"code\">CS-05</span>동시성</a>\n  <a href=\"#cs-q6\"><span class=\"code\">CS-06</span>OS 기본</a>\n  <a href=\"#cs-q7\"><span class=\"code\">CS-07</span>답변 비교</a>\n  <a href=\"#cs-q8\"><span class=\"code\">CS-08</span>시스템 현상 연결</a>\n  <a href=\"#cs-q9\"><span class=\"code\">CS-09</span>심화 답변 루브릭</a>\n  <a href=\"#cs-q10\"><span class=\"code\">CS-10</span>네트워크·메모리 압박</a>\n  <a href=\"#cs-q11\"><span class=\"code\">CS-11</span>동시성 검증 질문</a>\n  <a href=\"#cs-q12\"><span class=\"code\">CS-12</span>OS Network Internals Drill</a>\n  <a href=\"#cs-q13\"><span class=\"code\">CS-13</span>핵심 질문 30선</a>\n  <a href=\"#cs-q14\"><span class=\"code\">CS-14</span>개념 인과관계</a>\n  <a href=\"#doc-dbdeep\"><span class=\"code\">PART</span>DB 심화 면접</a>\n<a href=\"#dbdeep-q1\"><span class=\"code\">DBD-01</span>DB 심화 답변</a>\n  <a href=\"#dbdeep-q2\"><span class=\"code\">DBD-02</span>MVCC</a>\n  <a href=\"#dbdeep-q3\"><span class=\"code\">DBD-03</span>격리 수준</a>\n  <a href=\"#dbdeep-q4\"><span class=\"code\">DBD-04</span>락·deadlock</a>\n  <a href=\"#dbdeep-q5\"><span class=\"code\">DBD-05</span>lost update</a>\n  <a href=\"#dbdeep-q6\"><span class=\"code\">DBD-06</span>query planner·실행 계획</a>\n  <a href=\"#dbdeep-q7\"><span class=\"code\">DBD-07</span>인덱스 설계</a>\n  <a href=\"#dbdeep-q8\"><span class=\"code\">DBD-08</span>트랜잭션 경계</a>\n  <a href=\"#dbdeep-q9\"><span class=\"code\">DBD-09</span>Connection Pool</a>\n  <a href=\"#dbdeep-q10\"><span class=\"code\">DBD-10</span>WAL·복제</a>\n  <a href=\"#dbdeep-q11\"><span class=\"code\">DBD-11</span>백업·복구</a>\n  <a href=\"#dbdeep-q12\"><span class=\"code\">DBD-12</span>무중단 마이그레이션</a>\n  <a href=\"#dbdeep-q13\"><span class=\"code\">DBD-13</span>핵심 질문 35선</a>\n  <a href=\"#dbdeep-q14\"><span class=\"code\">DBD-14</span>MVCC Index Plan Deep Dive</a>\n  <a href=\"#dbdeep-q15\"><span class=\"code\">DBD-15</span>개념 인과관계</a>\n  <a href=\"#dbdeep-q16\"><span class=\"code\">DBD-16</span>실행계획 실전 해석</a>\n  <a href=\"#doc-security\"><span class=\"code\">PART</span>보안 심화 면접</a>\n<a href=\"#security-q1\"><span class=\"code\">SEC-01</span>보안 답변 프레임</a>\n  <a href=\"#security-q2\"><span class=\"code\">SEC-02</span>Threat Modeling·OWASP Top 10</a>\n  <a href=\"#security-q3\"><span class=\"code\">SEC-03</span>접근 제어·IDOR</a>\n  <a href=\"#security-q4\"><span class=\"code\">SEC-04</span>인증·세션</a>\n  <a href=\"#security-q5\"><span class=\"code\">SEC-05</span>OAuth2/OIDC</a>\n  <a href=\"#security-q6\"><span class=\"code\">SEC-06</span>JWT</a>\n  <a href=\"#security-q7\"><span class=\"code\">SEC-07</span>XSS·CSRF</a>\n  <a href=\"#security-q8\"><span class=\"code\">SEC-08</span>Injection</a>\n  <a href=\"#security-q9\"><span class=\"code\">SEC-09</span>SSRF</a>\n  <a href=\"#security-q10\"><span class=\"code\">SEC-10</span>비밀번호·Secret</a>\n  <a href=\"#security-q11\"><span class=\"code\">SEC-11</span>Multi-tenant</a>\n  <a href=\"#security-q12\"><span class=\"code\">SEC-12</span>감사 로그</a>\n  <a href=\"#security-q13\"><span class=\"code\">SEC-13</span>사고 대응</a>\n  <a href=\"#security-q14\"><span class=\"code\">SEC-14</span>핵심 질문 40선</a>\n  <a href=\"#security-q15\"><span class=\"code\">SEC-15</span>Attack Path 답변</a>\n  <a href=\"#security-q16\"><span class=\"code\">SEC-16</span>Exploit Chain Validation</a>\n  <a href=\"#security-q17\"><span class=\"code\">SEC-17</span>개념 인과관계</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : CAREER-CORE-DEEP-DIVE</span>\n    <span>SCOPE : CS · DATABASE · SECURITY</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>CS·DB·보안 심화 면접</h1>\n  <p class=\"hero-sub\">CS 기본기, DB 심화, 보안 심화 면접을 핵심 개념 검증 흐름으로 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED INTERVIEW PATH · SOURCES : 3 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>학습 로드맵</h2></div>\n<p class=\"lede\">이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다.</p>\n<ul><li>CS 기본기 면접</li><li>DB 심화 면접</li><li>보안 심화 면접</li></ul>\n</section>\n\n<section id=\"career-readiness-gate\">\n<div class=\"ch-head\"><span class=\"ch-code\">GATE</span><h2>CAREER READINESS GATE</h2></div>\n<p class=\"lede\"><strong>CS·DB·보안 심화 답변 게이트</strong>는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">CS·DB·보안 심화 답변 게이트</span>\nCS, DB, 보안 개념을 정의 암기가 아니라 장애, 성능, 공격 경로를 줄이는 판단 기준으로 설명한다.\n</div>\n<table>\n<tr><th>준비 결과</th><th>면접에서 보여야 하는 신호</th><th>미달 신호</th></tr>\n<tr><td>30초 결론</td><td>첫 문장에서 판단 기준과 결론이 나온다.</td><td>배경 설명이 길고 질문의 핵심을 늦게 잡는다.</td></tr>\n<tr><td>90초 확장</td><td>대안, trade-off, 실패 모드, 검증 증거가 이어진다.</td><td>장점만 말하고 깨지는 조건을 말하지 못한다.</td></tr>\n<tr><td>압박 꼬리질문</td><td>모르는 범위와 직접 경험 범위를 분리한 뒤 확인 방법을 말한다.</td><td>직접 하지 않은 일을 경험처럼 포장한다.</td></tr>\n</table>\n<ul><li>동시성 질문을 race condition, lock, invariant, 재현 조건, 테스트 아이디어로 연결한다.</li><li>DB 질문을 MVCC, isolation anomaly, index plan, WAL, replication lag, zero-downtime migration으로 확장한다.</li><li>보안 질문을 OWASP 키워드가 아니라 source, trust boundary, sink, audit evidence로 추적한다.</li></ul>\n</section>\n\n<section id=\"career-answer-rubric\">\n<div class=\"ch-head\"><span class=\"ch-code\">RUBRIC</span><h2>ANSWER QUALITY RUBRIC</h2></div>\n<p class=\"lede\">답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다.</p>\n<table>\n<tr><th>등급</th><th>답변 상태</th><th>보정 기준</th></tr>\n<tr><td>S</td><td>결론, 기준, trade-off, 실패 모드, 검증 증거, 본인 기여가 모두 분리된다.</td><td>압박 질문 2개를 붙여도 같은 경계와 증거를 유지한다.</td></tr>\n<tr><td>A</td><td>핵심 개념과 실무 예시는 좋지만 수치나 산출물 증거가 일부 비어 있다.</td><td>PR·ADR·지표·장애기록·QA ticket 중 최소 2개를 붙인다.</td></tr>\n<tr><td>B</td><td>개념 설명은 가능하지만 경험, 대안, 실패 조건이 약하다.</td><td>직접 경험, 일부 참여, 설계 지식을 문장 안에서 분리한다.</td></tr>\n<tr><td>C</td><td>기술명과 기능 목록 중심이고 면접관이 기여도와 판단 기준을 확인하기 어렵다.</td><td>질문을 다시 정의하고 30초 결론부터 재작성한다.</td></tr>\n</table>\n</section>\n\n<section id=\"career-pressure-loop\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOOP</span><h2>PRESSURE RESPONSE LOOP</h2></div>\n<p class=\"lede\">압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">PRESSURE RESPONSE LOOP</span>\n1. 질문을 한 문장으로 재정의한다<br>\n2. 직접 경험 / 일부 경험 / 설계 지식을 분리한다<br>\n3. 판단 기준 2개만 말한다<br>\n4. 증거 하나와 실패 모드 하나를 붙인다<br>\n5. 남은 불확실성은 검증 계획으로 닫는다\n</div>\n<table>\n<tr><th>압박 질문</th><th>복구 답변</th><th>피해야 할 방향</th></tr>\n<tr><td>그건 정의 아닌가요? 실제 장애나 공격에서는 어떻게 보이나요?</td><td>정의 한 줄 뒤에 깨지는 조건, 관측 증거, 완화책, 재발 방지 순서로 답변을 재구성한다.</td><td>질문을 피하려고 일반론을 길게 늘리는 것</td></tr>\n<tr><td>그건 본인이 한 일인가요?</td><td>본인 결정, 팀 결정, 외부 제약을 분리하고 본인이 소유한 판단만 말한다.</td><td>팀 성과 전체를 개인 성과처럼 말하는 것</td></tr>\n<tr><td>수치나 증거가 없으면 어떻게 확인하나요?</td><td>정량 지표가 없었던 한계를 인정하고, 재현 절차·QA ticket·before/after·PR diff 같은 대체 증거를 제시한다.</td><td>좋아졌다고만 말하는 것</td></tr>\n</table>\n</section>\n\n<section id=\"career-evidence-packet\">\n<div class=\"ch-head\"><span class=\"ch-code\">EVIDENCE</span><h2>EVIDENCE PACKET</h2></div>\n<p class=\"lede\">면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다.</p>\n<table>\n<tr><th>증거 묶음</th><th>준비할 항목</th><th>면접에서 쓰는 방식</th></tr>\n<tr><td>핵심 산출물</td><td>실행 계획, 동시성 테스트 시나리오, 위협 모델, PR·ADR·지표·장애기록·QA ticket</td><td>주장 뒤에 바로 붙일 수 있는 근거로 정리한다.</td></tr>\n<tr><td>공통 증거</td><td>PR·ADR·지표·장애기록·QA ticket</td><td>기술 판단, 협업 합의, 결과 확인을 한 번에 보여준다.</td></tr>\n<tr><td>답변 카드</td><td>질문, 30초 결론, 90초 확장, 압박 꼬리질문, 위험 표현, 대체 문장</td><td>면접 전날 같은 질문을 다시 말하며 품질을 점검한다.</td></tr>\n</table>\n</section>\n\n<section id=\"career-output-packet\">\n<div class=\"ch-head\"><span class=\"ch-code\">OUTPUT</span><h2>CAREER OUTPUT PACKET</h2></div>\n<p class=\"lede\">A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다.</p>\n<pre class=\"snippet-card\"><code>career_output_packet:\n  document: career-core-deep-dive\n  target_gate: \"CS·DB·보안 심화 답변 게이트\"\n  before_answer: \"도구명, 역할명, 감상 중심으로 말해 기여 범위와 결과가 흐릿한 답변\"\n  after_answer: \"질문 재정의 → 본인 결정 범위 → 판단 기준 → 버린 대안 → 전후 증거 → 남은 리스크 순서의 답변\"\n  evidence_to_attach:\n    - 실행 계획\n    - 동시성 테스트 시나리오\n    - PR/ADR/metric/incident record/QA ticket\n    - reviewer_follow_up_answer\n  interview_use: \"30초 결론은 after_answer의 첫 두 줄로 말하고, 90초 확장은 evidence_to_attach와 pressure response로 확장한다\"</code></pre>\n<table>\n<tr><th>Before</th><th>After</th><th>검증 질문</th></tr>\n<tr><td>“CS, DB, 보안 개념을 정의 암기가 아니라 장애, 성능, 공격 경로를 줄이는 판단 기준으로 설명한다.”를 감상처럼 길게 설명한다.</td><td>동시성 질문을 race condition, lock, invariant, 재현 조건, 테스트 아이디어로 연결한다.</td><td>본인 결정, 수치, 산출물, 실패 조건이 한 문장 안에 보이는가?</td></tr>\n<tr><td>“팀에서 처리했습니다”처럼 소유권이 흐릿하다.</td><td>정의 한 줄 뒤에 깨지는 조건, 관측 증거, 완화책, 재발 방지 순서로 답변을 재구성한다.</td><td>직접 경험과 설계 지식의 경계가 분리되어 있는가?</td></tr>\n</table>\n</section>\n\n<section id=\"career-final-drill\">\n<div class=\"ch-head\"><span class=\"ch-code\">DRILL</span><h2>FINAL 10 MINUTE DRILL</h2></div>\n<p class=\"lede\">면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다.</p>\n<table>\n<tr><th>시간</th><th>할 일</th><th>완료 기준</th></tr>\n<tr><td>0-3분</td><td>CS·DB·보안 심화 답변 게이트 질문 하나를 30초 결론으로 말한다.</td><td>첫 문장에 결론과 판단 기준이 있다.</td></tr>\n<tr><td>3-6분</td><td>같은 질문을 90초 확장으로 말한다.</td><td>대안, trade-off, 실패 모드, 증거가 포함된다.</td></tr>\n<tr><td>6-8분</td><td>압박 꼬리질문 하나를 붙여 답변을 복구한다.</td><td>모르는 범위를 숨기지 않고 확인 방법으로 닫는다.</td></tr>\n<tr><td>8-10분</td><td>DANGEROUS PHRASES를 제거하고 대체 문장으로 바꾼다.</td><td>추상 표현 없이 본인 기여와 증거가 남는다.</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">DANGEROUS PHRASES</span>\n<p>“많이 해봤습니다”, “대충 알고 있습니다”, “그냥 최적화했습니다”, “팀에서 처리했습니다”처럼 범위와 증거가 없는 표현은 약하게 들립니다. “제가 소유한 결정은 A이고, B 제약 때문에 C를 선택했으며, 결과는 D 증거로 확인했습니다”로 바꿉니다.</p>\n</div>\n</section>\n\n<section id=\"doc-cs\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>CS 기본기 면접</h2></div>\n</section>\n\n<section id=\"cs-q1\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-01</span><h2>Q. Big-O 시간/공간 복잡도는 어떻게 설명하나요?</h2></div>\n<h3>핵심 개념</h3><p>Big-O는 입력 크기가 커질 때 실행 시간이나 메모리 사용량이 어떻게 증가하는지 상한 관점으로 표현합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Big-O는 특정 컴퓨터에서 몇 ms 걸리는지를 맞히는 도구가 아니라 입력이 커질 때 비용이 어떤 모양으로 증가하는지 보는 언어입니다. 낮은 차수 항과 상수를 버리는 이유는 큰 입력에서 지배적인 증가율을 보기 위해서입니다. 다만 실무에서는 입력 크기, 호출 빈도, I/O 비용, 메모리 locality 때문에 이론 복잡도만으로 판단하면 안 됩니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">Big-O는 입력 n이 커질 때 비용 증가 추세를 보는 표기입니다. O(1), O(log n), O(n), O(n log n), O(n²)처럼 표현하며, 실무에서는 데이터가 커졌을 때 현재 알고리즘이 버틸 수 있는지 판단하는 데 씁니다.</div>\n<h3>90초 답변</h3><p>상수 시간도 실제로는 상수가 크면 느릴 수 있고, O(n)도 n이 작으면 충분할 수 있습니다. 면접에서는 “이중 루프라 O(n²)입니다”보다 입력 크기, 호출 빈도, 메모리 trade-off, 캐시/DB 같은 외부 비용을 함께 말하면 좋습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>공간 복잡도?</td><td>추가 자료구조나 recursion stack이 쓰는 메모리 증가량입니다.</td></tr><tr><td>O(log n) 예?</td><td>정렬된 배열 binary search, balanced tree 탐색입니다.</td></tr><tr><td>실무 연결?</td><td>대용량 grid filtering, API pagination, DB scan 비용으로 연결합니다.</td></tr></table>\n</section>\n\n<section id=\"cs-q2\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-02</span><h2>Q. Array/List/Map/Set/Heap/Queue/Stack/Tree/Graph는 언제 쓰나요?</h2></div>\n<h3>핵심 개념</h3><p>자료구조 선택은 접근 패턴, 삽입/삭제 비용, 정렬 필요성, 중복 허용, 우선순위, 관계 표현에 따라 달라집니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>자료구조는 데이터를 담는 통이 아니라 필요한 연산의 비용표입니다. Array는 index 접근이 빠르지만 중간 삽입/삭제가 비싸고, HashMap은 평균 조회가 빠르지만 hash 품질과 resize 비용이 있습니다. Tree와 Heap처럼 구조적 제약을 둔 자료구조는 정렬, 우선순위, 범위 탐색 같은 특정 요구를 위해 일반성을 포기합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">순서 기반 index 접근은 Array/List, key 기반 조회는 Map, 중복 제거와 membership check는 Set, 우선순위 처리는 Heap, FIFO는 Queue, LIFO는 Stack, 계층은 Tree, 복잡한 관계는 Graph를 씁니다.</div>\n<h3>90초 답변</h3><p>면접에서는 자료구조 이름보다 비용을 말해야 합니다. HashMap 조회는 평균 O(1)이지만 hash collision과 resize 비용이 있고, TreeMap은 O(log n)이지만 정렬 순서를 유지합니다. Queue는 작업 처리, Stack은 call stack/undo, Heap은 top-k나 scheduler에 연결할 수 있습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>Set 중복 기준?</td><td>equals/hashCode 또는 비교 기준에 따라 달라집니다.</td></tr><tr><td>Heap 정렬?</td><td>최솟값/최댓값을 빠르게 꺼내는 데 유리합니다.</td></tr><tr><td>Graph 저장?</td><td>인접 리스트와 인접 행렬을 규모와 밀도에 따라 선택합니다.</td></tr></table>\n</section>\n\n<section id=\"cs-q3\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-03</span><h2>Q. Hash collision은 무엇이고 왜 중요한가요?</h2></div>\n<h3>핵심 개념</h3><p>Hash collision은 서로 다른 key가 같은 hash bucket에 배치되는 현상입니다. 충돌이 많으면 HashMap의 평균 O(1) 성능이 나빠집니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>hash collision은 예외 상황이 아니라 hash 공간이 유한하기 때문에 언제든 생길 수 있는 정상 현상입니다. 좋은 hash 함수는 key를 고르게 분산시켜 bucket 길이를 짧게 유지하고, 최종 동등성은 <code>equals</code>가 판단합니다. collision이 많아지면 평균 O(1)이라는 기대가 깨지고, 공격자가 의도적으로 몰리게 만들면 보안 이슈가 될 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">HashMap은 hashCode로 bucket을 찾고 equals로 실제 key를 비교합니다. 서로 다른 key가 같은 bucket에 몰리는 Hash collision이 많으면 조회 성능이 떨어지고, equals/hashCode 계약이 깨지면 조회 자체가 실패할 수 있습니다.</div>\n<h3>90초 답변</h3><p>좋은 hash 함수는 key를 bucket에 고르게 분산시켜야 합니다. Java HashMap은 충돌이 심하면 bucket 구조를 tree로 바꾸는 최적화가 있지만, 기본적으로 equals/hashCode를 올바르게 구현해야 합니다. 보안 관점에서는 의도적인 hash flooding 공격도 고려할 수 있습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>equals가 true면?</td><td>hashCode도 반드시 같아야 합니다.</td></tr><tr><td>hashCode 같으면 equals true?</td><td>아닙니다. 충돌 가능성이 있습니다.</td></tr><tr><td>mutable key?</td><td>Map에 넣은 뒤 hash 기준 값이 바뀌면 찾지 못할 수 있습니다.</td></tr></table>\n</section>\n\n<section id=\"cs-q4\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-04</span><h2>Q. BFS/DFS는 언제 쓰나요?</h2></div>\n<h3>핵심 개념</h3><p>BFS는 가까운 노드부터 넓게 탐색하고, DFS는 한 경로를 깊게 탐색합니다. 그래프/트리 탐색의 기본입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>BFS와 DFS의 차이는 방문 순서가 아니라 문제의 증거를 어떤 순서로 찾는가입니다. BFS는 같은 거리의 노드를 먼저 모두 확인하므로 무가중치 최단 거리와 단계별 확산에 적합합니다. DFS는 한 경로를 끝까지 파고들기 때문에 조합 탐색, cycle detection, dependency 탐색에서 자연스럽지만 깊이가 크면 stack 위험이 있습니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">BFS는 queue를 사용해 최단 거리나 단계별 탐색에 유리하고, DFS는 stack 또는 recursion으로 깊은 경로 탐색, cycle detection, backtracking에 자주 씁니다.</div>\n<h3>90초 답변</h3><p>무가중치 그래프의 최단 경로는 BFS가 적합합니다. DFS는 모든 조합 탐색이나 dependency graph에서 cycle을 찾는 데 유용합니다. 실무에서는 메뉴 트리, 권한 그래프, 빌드 dependency, 조직도, workflow graph 같은 문제로 연결해 설명할 수 있습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>visited가 왜 필요?</td><td>cycle이 있는 그래프에서 무한 반복을 막기 위해 필요합니다.</td></tr><tr><td>DFS recursion 위험?</td><td>깊이가 크면 stack overflow가 날 수 있어 iterative 방식이 필요할 수 있습니다.</td></tr><tr><td>가중치 최단 경로?</td><td>Dijkstra 같은 알고리즘을 검토합니다.</td></tr></table>\n</section>\n\n<section id=\"cs-q5\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-05</span><h2>Q. race condition, deadlock, mutex/semaphore를 설명해보세요.</h2></div>\n<h3>핵심 개념</h3><p>race condition은 실행 순서에 따라 결과가 달라지는 문제입니다. deadlock은 둘 이상의 작업이 서로가 가진 자원을 기다리며 멈추는 상태입니다. mutex는 상호 배제, semaphore는 제한된 개수의 permit으로 동시 접근을 제어합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>동시성 문제는 코드가 틀렸다기보다 가능한 실행 순서가 너무 많아 일부 순서에서 불변식이 깨지는 문제입니다. mutex는 공유 자원에 한 번에 하나만 들어가게 하고, semaphore는 제한된 수만 들어가게 합니다. deadlock은 네 가지 조건이 동시에 맞을 때 생기므로 lock 순서, timeout, 범위 축소로 조건을 깨는 식으로 접근합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">공유 상태를 여러 thread가 동시에 수정하면 race condition이 생길 수 있어 lock, atomic operation, transaction으로 보호합니다. deadlock은 lock 순서 불일치가 대표 원인이고, mutex는 하나만 들어가게, semaphore는 정해진 수만 들어가게 제어합니다.</div>\n<h3>90초 답변</h3><p>실무에서는 중복 클릭, 중복 결제, 재고 차감, DB row lock, thread pool 고갈 같은 문제로 나타납니다. deadlock 예방은 lock 순서 통일, lock 범위 축소, timeout, retry가 기본입니다. 동시성 문제는 재현이 어렵기 때문에 테스트와 로그, transaction isolation 이해가 필요합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>atomic?</td><td>중간 상태를 다른 작업이 볼 수 없는 단위 연산입니다.</td></tr><tr><td>semaphore 예?</td><td>DB connection pool처럼 동시에 사용할 수 있는 자원 수 제한입니다.</td></tr><tr><td>frontend 연결?</td><td>중복 요청, stale response, optimistic update 충돌로 나타날 수 있습니다.</td></tr></table>\n</section>\n\n<section id=\"cs-q6\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-06</span><h2>Q. process vs thread, context switching, memory, file descriptor를 설명해보세요.</h2></div>\n<h3>핵심 개념</h3><p>process는 독립된 실행 단위와 주소 공간을 가지고, thread는 process 안에서 메모리를 공유하는 실행 흐름입니다. context switching은 CPU가 실행 대상을 바꾸며 상태를 저장/복원하는 비용입니다. file descriptor는 열린 파일, socket 같은 OS resource를 가리키는 핸들입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>process는 격리된 주소 공간과 자원을 가진 실행 단위이고, thread는 같은 process 안에서 메모리를 공유하는 실행 흐름입니다. thread는 가볍지만 공유 메모리 때문에 race condition이 생기고, process는 격리가 강하지만 IPC와 전환 비용이 큽니다. file descriptor는 파일뿐 아니라 socket, pipe 같은 OS 자원 핸들이므로 누수되면 네트워크 서버가 새 연결을 받지 못할 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">process는 메모리 공간이 분리되어 안정적이지만 생성/전환 비용이 크고, thread는 같은 process 메모리를 공유해 가볍지만 동시성 버그가 생길 수 있습니다. context switching이 많으면 CPU가 실제 작업보다 전환에 시간을 쓰고, file descriptor가 누수되면 파일이나 socket을 더 열 수 없습니다.</div>\n<h3>90초 답변</h3><p>웹 서버에서 thread pool이 고갈되면 요청이 대기하고, DB connection pool이 작거나 누수되면 API가 멈춘 것처럼 보입니다. socket도 file descriptor로 관리되므로 connection leak은 FD 고갈로 이어질 수 있습니다. OS 기본기를 알면 “서버가 느리다”를 CPU, memory, thread, FD, network로 나눠 볼 수 있습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>memory leak?</td><td>더 이상 필요 없는 객체나 resource가 참조/해제되지 않아 계속 남는 상태입니다.</td></tr><tr><td>context switching 비용?</td><td>register/cache 상태 전환 비용과 scheduler overhead가 있습니다.</td></tr><tr><td>FD 확인?</td><td>lsof, ulimit, proc filesystem 등으로 확인할 수 있습니다.</td></tr></table>\n</section>\n\n<section id=\"cs-q7\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-07</span><h2>나쁜 답변 / 좋은 답변 비교</h2></div>\n<table>\n<tr><th>질문</th><th>나쁜 답변</th><th>좋은 답변</th></tr>\n<tr><td>Big-O</td><td>빠른지 느린지 보는 겁니다.</td><td>입력 증가에 따른 비용 증가율을 보고, 실제 입력 크기와 호출 빈도, 메모리 trade-off까지 함께 판단합니다.</td></tr>\n<tr><td>deadlock</td><td>프로그램이 멈추는 겁니다.</td><td>서로의 lock을 기다리는 상태이며 lock 순서 통일, timeout, retry, transaction 범위 축소로 예방합니다.</td></tr>\n<tr><td>process vs thread</td><td>process가 크고 thread가 작습니다.</td><td>process는 주소 공간이 분리되고 thread는 메모리를 공유하므로 성능과 격리, 동시성 위험이 달라집니다.</td></tr>\n</table>\n</section>\n\n<section id=\"cs-q8\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-08</span><h2>Q. CS 지식을 실제 장애·성능 현상과 어떻게 연결하나요?</h2></div>\n<p class=\"lede\">면접에서 CS 기본기가 깊어 보이는 순간은 정의를 말할 때가 아니라, 운영 현상을 OS·네트워크·런타임 개념으로 분해할 때입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">CS SYSTEM TRACE</span>\n“API가 느립니다”라는 현상을 CPU, memory, thread, event loop, file descriptor, DB connection, network latency로 나누어 봅니다. CPU가 낮아도 thread pool이 꽉 차 있거나, FD가 고갈되었거나, downstream timeout 때문에 요청이 대기할 수 있습니다. 그래서 지표를 한 개만 보지 않고 queue length, active thread, GC pause, socket state, connection pool wait time을 함께 확인합니다.\n</div>\n<table>\n<tr><th>현상</th><th>관련 CS 개념</th><th>전문적인 답변 방향</th></tr>\n<tr><td>CPU는 낮은데 응답이 느림</td><td>I/O wait, blocking call, thread pool saturation</td><td>실행 시간이 아니라 대기 시간이 병목일 수 있으므로 thread dump, pool wait, downstream latency를 봅니다.</td></tr>\n<tr><td>간헐적 timeout</td><td>queueing, tail latency, retry amplification</td><td>평균 latency보다 p95/p99와 retry 폭증, connection reuse, timeout budget을 확인합니다.</td></tr>\n<tr><td>메모리가 계속 증가</td><td>heap, GC, resource leak, retained reference</td><td>객체 수명과 참조 경로, cache eviction, listener/socket close 여부를 확인합니다.</td></tr>\n<tr><td>동시 요청에서 값이 꼬임</td><td>race condition, atomicity, visibility</td><td>공유 상태와 불변식이 어떤 순서에서 깨지는지 추적하고 lock, transaction, idempotency를 검토합니다.</td></tr>\n<tr><td>서버가 새 연결을 못 받음</td><td>file descriptor, socket lifecycle, backlog</td><td>FD 한도, CLOSE_WAIT, accept queue, keep-alive 설정, connection leak을 확인합니다.</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">답변 패턴</span>\n<p>“정의 → 발생 조건 → 관측 지표 → 해결 선택지 → trade-off” 순서로 말합니다. 예를 들어 context switching은 “CPU가 작업을 바꾸는 비용”에서 끝내지 말고 thread가 과도하게 많을 때 cache miss와 scheduler overhead가 늘고, 해결책은 pool 크기 조정과 blocking 구간 축소이며, 너무 줄이면 처리량이 떨어진다는 trade-off까지 연결합니다.</p>\n</div>\n</section>\n\n<section id=\"cs-q9\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-09</span><h2>CS 면접 답변 심화 루브릭</h2></div>\n<p class=\"lede\">암기 답변과 전문 답변은 같은 키워드를 쓰더라도 검증 가능한 근거를 붙이는지에서 갈립니다.</p>\n<table>\n<tr><th>루브릭</th><th>부실한 답변</th><th>출판 가능한 답변 기준</th></tr>\n<tr><td>입력 규모</td><td>“O(n)이라 괜찮습니다.”</td><td>n의 범위, 호출 빈도, 메모리 비용, I/O 비용을 함께 말합니다.</td></tr>\n<tr><td>불변식</td><td>“lock을 걸면 됩니다.”</td><td>어떤 공유 상태의 어떤 조건이 깨지는지 먼저 설명합니다.</td></tr>\n<tr><td>실패 모드</td><td>“retry하면 됩니다.”</td><td>중복 실행, 순서 역전, timeout budget, retry storm 가능성을 같이 다룹니다.</td></tr>\n<tr><td>관측 근거</td><td>“느릴 것 같습니다.”</td><td>CPU, memory, thread, GC, latency percentile, queue length처럼 확인 지표를 제시합니다.</td></tr>\n<tr><td>대안 비교</td><td>“HashMap이 빠릅니다.”</td><td>HashMap, TreeMap, array scan, DB index처럼 선택지를 비용과 제약으로 비교합니다.</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">CS DEPTH RUBRIC</span>\n좋은 CS 답변은 “용어를 안다”가 아니라 “제약에서 선택을 도출한다”입니다. 면접 중에는 먼저 문제 규모와 불변식을 확인하고, 그다음 자료구조·동시성 제어·OS 자원·네트워크 비용 중 무엇이 핵심 병목인지 좁히는 방식으로 답합니다.\n</div>\n</section>\n\n<section id=\"cs-q10\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-10</span><h2>네트워크·메모리 압박 질문</h2></div>\n<p class=\"lede\">CS 기본기 면접은 알고리즘만 묻지 않습니다. 웹 개발자에게는 네트워크, 메모리, 런타임 자원까지 연결해 묻는 경우가 많습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">CS NETWORK MEMORY DRILL</span>\n“브라우저에서 API 요청이 느립니다”라는 질문에는 DNS, TCP handshake, TLS, HTTP keep-alive, server queue, DB query, response serialization, browser parsing을 순서대로 나눕니다. “메모리가 샙니다”라는 질문에는 heap object, native resource, event listener, closure, cache, file descriptor를 나눠 봅니다.\n</div>\n<table>\n<tr><th>압박 질문</th><th>얕은 답변</th><th>좋은 답변</th></tr>\n<tr><td>TCP와 HTTP 차이는?</td><td>TCP는 전송, HTTP는 웹입니다.</td><td>TCP는 신뢰성 있는 byte stream이고 HTTP는 그 위에서 request/response 의미를 정의하는 application protocol입니다. 지연은 handshake, congestion, keep-alive, server processing으로 나눠 봅니다.</td></tr>\n<tr><td>메모리 누수는 GC가 막아주지 않나요?</td><td>GC가 알아서 치웁니다.</td><td>GC는 도달 불가능한 객체만 회수합니다. cache, static reference, listener, closure, ThreadLocal이 계속 참조하면 논리적으로 필요 없어도 회수되지 않습니다.</td></tr>\n<tr><td>CPU가 낮은데 왜 느릴까요?</td><td>네트워크 문제 같습니다.</td><td>I/O wait, lock wait, thread pool saturation, DB connection wait, downstream timeout처럼 CPU를 쓰지 않고 대기하는 병목을 의심합니다.</td></tr>\n<tr><td>p99가 중요한 이유는?</td><td>느린 사용자도 있기 때문입니다.</td><td>평균은 tail latency를 숨깁니다. queueing과 retry가 겹치면 일부 요청이 전체 사용자 경험과 장애 전파를 결정합니다.</td></tr>\n</table>\n<h3>면접에서 말할 증거</h3>\n<p>waterfall, TCP reuse, TLS handshake time, p95/p99 latency, heap snapshot, retained path, FD count, thread dump, pool wait time을 말합니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">주의</span>\n<p>네트워크와 메모리를 “느리다/샌다” 정도로 말하면 초안 수준입니다. 어느 계층에서 어떤 자원이 대기하거나 유지되는지 쪼개야 합니다.</p>\n</div>\n</section>\n\n<section id=\"cs-q11\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-11</span><h2>동시성 검증 질문</h2></div>\n<p class=\"lede\">동시성 답변은 lock 이름을 아는 것보다 불변식이 어떤 interleaving에서 깨지는지 설명하는 것이 핵심입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">CONCURRENCY INVARIANT CHECK</span>\n동시성 문제를 받으면 공유 상태, 읽기-수정-쓰기 순서, 원자성 경계, visibility, 실패 시 재시도 가능성을 먼저 봅니다. “lock을 겁니다”가 아니라 어떤 invariant를 보호하고 lock 범위를 어디까지 둘지 말해야 합니다.\n</div>\n<table>\n<tr><th>질문</th><th>답변 기준</th><th>놓치기 쉬운 점</th></tr>\n<tr><td>재고 차감 중복 요청</td><td>재고가 0 미만이 되지 않는 invariant를 DB transaction, row lock, optimistic lock, idempotency로 보호합니다.</td><td>API retry와 사용자 더블클릭이 같은 중복 문제를 만들 수 있습니다.</td></tr>\n<tr><td>낙관적 락 충돌</td><td>version 조건 update 실패를 감지하고 사용자 재시도 또는 merge 정책을 둡니다.</td><td>무한 retry는 부하를 키울 수 있습니다.</td></tr>\n<tr><td>캐시와 DB 동시 갱신</td><td>source of truth, invalidation 순서, stale read 허용 범위, outbox/event 기반 보정을 말합니다.</td><td>DB commit 전 캐시를 바꾸면 실패 시 불일치가 생깁니다.</td></tr>\n<tr><td>분산 lock</td><td>lease, timeout, fencing token, lock holder 장애를 함께 봅니다.</td><td>lock 획득 성공만으로 안전하지 않습니다.</td></tr>\n<tr><td>thread-safe collection</td><td>개별 연산 안전과 복합 연산 안전을 구분합니다.</td><td>contains 후 put 같은 check-then-act는 여전히 race가 날 수 있습니다.</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">흔한 오답</span>\n<p>동시성 문제를 “synchronized를 쓰면 됩니다”로 끝내면 부족합니다. 단일 프로세스 lock인지, DB transaction인지, 분산 환경인지에 따라 보호 범위가 달라집니다.</p>\n</div>\n</section>\n\n<section id=\"cs-q12\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-12</span><h2>OS NETWORK INTERNALS DRILL</h2></div>\n<p class=\"lede\">심화 CS 면접은 정의 암기에서 끝나지 않고, 요청 하나가 OS·네트워크·런타임을 지나며 어떤 비용과 실패 모드를 만드는지 시간순으로 설명하게 합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">OS NETWORK INTERNALS DRILL</span>\n브라우저가 API를 호출하면 DNS 조회 후 TCP 3-way handshake, TLS handshake, HTTP request 전송, 서버 accept, kernel/user mode 전환, application handler, DB/network I/O, response write, TCP ACK 흐름이 이어집니다. keep-alive와 connection pool이 있으면 일부 handshake는 생략되지만, TLS 재협상, packet loss, head-of-line blocking, server queue 대기는 여전히 tail latency를 만들 수 있습니다.\n</div>\n<h3>메모리와 커널 경계</h3>\n<p>virtual memory는 process마다 독립된 주소 공간을 제공하고, page table을 통해 virtual address를 physical frame에 매핑합니다. 접근한 page가 메모리에 없거나 권한이 맞지 않으면 page fault가 발생하며, 정상적인 minor fault는 매핑만 보정하고 major fault는 disk I/O를 동반할 수 있습니다. page cache는 파일과 socket I/O의 반복 접근을 빠르게 하지만, cache pressure가 커지면 reclaim과 writeback이 응답 지연으로 보일 수 있습니다. system call은 user mode에서 kernel mode로 넘어가므로 너무 잦은 read/write, context switching, copy 비용도 병목이 됩니다.</p>\n<h3>TCP/TLS/HTTP 타임라인</h3>\n<table>\n<tr><th>단계</th><th>확인할 내부 동작</th><th>면접 답변 포인트</th></tr>\n<tr><td>DNS</td><td>cache hit, resolver 지연, TTL</td><td>첫 요청만 느린지, 특정 region에서만 느린지 분리합니다.</td></tr>\n<tr><td>TCP</td><td>SYN/SYN-ACK/ACK, congestion window, retransmission</td><td>packet loss와 handshake 비용은 p95/p99를 악화시킬 수 있습니다.</td></tr>\n<tr><td>TLS</td><td>certificate 검증, key exchange, session resumption</td><td>새 연결이 많으면 CPU와 latency가 증가하고 keep-alive가 중요합니다.</td></tr>\n<tr><td>HTTP</td><td>header/body, keep-alive, HTTP/2 multiplexing, server queue</td><td>application 처리 전 대기 시간이 waterfall에 나타날 수 있습니다.</td></tr>\n<tr><td>OS I/O</td><td>socket buffer, epoll/kqueue, kernel/user copy, page cache</td><td>CPU가 낮아도 I/O wait와 buffer pressure가 병목일 수 있습니다.</td></tr>\n</table>\n<h3>동시성 내부 모델</h3>\n<p>happens-before는 한 작업의 write가 다른 작업의 read에 관측될 수 있음을 보장하는 순서 관계입니다. lock, volatile, channel, thread start/join 같은 동기화 지점이 없으면 CPU cache와 compiler reorder 때문에 값이 보이지 않을 수 있습니다. CAS는 compare-and-swap으로 lock 없이 상태를 바꾸는 원자 연산이지만, 값이 A에서 B로 갔다가 다시 A가 되는 ABA 문제를 놓칠 수 있어 version stamp나 hazard pointer 같은 보완이 필요합니다. thread pool starvation은 pool 안 작업이 같은 pool의 다른 작업 완료를 기다리거나 blocking I/O가 pool을 모두 점유할 때 발생하며, 별도 executor, bounded queue, timeout, backpressure로 완화합니다.</p>\n<div class=\"callout warn\"><span class=\"co-label\">압박 포인트</span><p>“CPU가 낮은데 API가 느립니다”라는 질문에는 thread pool starvation, connection pool wait, kernel I/O wait, page fault, TLS handshake, DNS 지연을 같은 타임라인 위에 올려서 좁혀야 합니다.</p></div>\n</section>\n\n<section id=\"cs-q13\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-13</span><h2>핵심 질문 30선과 구체 답변 훈련</h2></div>\n<p class=\"lede\">아래 질문은 키워드 암기가 아니라 면접장에서 바로 말할 수 있는 구체 상황형 질문입니다.</p>\n<table>\n<tr><th>번호</th><th>구체 질문</th><th>답변 방향</th></tr>\n<tr><td>1</td><td>HashMap 조회가 평균 O(1)인데도 대량 요청에서 느려진다면 어떤 원인을 의심하나요?</td><td>collision, resize, hash 품질, key mutation, cache locality, 동시성 경합을 분리합니다.</td></tr>\n<tr><td>2</td><td>무가중치 그래프 최단 경로는 왜 DFS보다 BFS가 적합한가요?</td><td>BFS가 거리 k 노드를 모두 본 뒤 k+1로 넘어가므로 처음 도달이 최단입니다.</td></tr>\n<tr><td>3</td><td>프로세스 격리와 스레드 공유 메모리 차이가 장애 격리에 어떤 영향을 주나요?</td><td>process는 주소 공간 격리가 강하고 thread는 저렴하지만 공유 상태 오염 위험이 큽니다.</td></tr>\n<tr><td>4</td><td>context switching이 많아졌다는 지표를 보면 어떤 설계 문제를 의심하나요?</td><td>과도한 thread 수, blocking I/O, lock 경합, 작은 작업의 과도한 분할을 봅니다.</td></tr>\n<tr><td>5</td><td>virtual memory에서 page fault가 항상 장애나 버그는 아닌 이유는 무엇인가요?</td><td>lazy allocation과 file mapping의 정상 경로일 수 있고, major fault가 많을 때 I/O 병목을 의심합니다.</td></tr>\n<tr><td>6</td><td>page cache 때문에 파일 읽기 benchmark가 왜 오해를 만들 수 있나요?</td><td>두 번째 실행은 disk가 아니라 memory cache를 읽을 수 있어 cold/warm cache를 구분해야 합니다.</td></tr>\n<tr><td>7</td><td>브라우저 요청의 TCP/TLS/HTTP 타임라인을 어디까지 쪼개 설명할 수 있나요?</td><td>DNS, TCP handshake, TLS, request queue, server processing, response transfer, reuse 여부를 말합니다.</td></tr>\n<tr><td>8</td><td>kernel/user mode 전환 비용은 어떤 코드에서 문제가 되나요?</td><td>작은 read/write 반복, logging 폭증, system call 과다, context switch가 많은 서버에서 커집니다.</td></tr>\n<tr><td>9</td><td>happens-before가 없는 공유 변수 읽기는 왜 간헐적으로만 실패하나요?</td><td>CPU cache, reorder, scheduler interleaving에 따라 visibility가 달라져 재현성이 낮습니다.</td></tr>\n<tr><td>10</td><td>CAS가 lock보다 항상 낫지 않은 이유는 무엇인가요?</td><td>retry loop가 경쟁에서 CPU를 태우고 ABA, starvation, 복합 invariant 보호 한계가 있습니다.</td></tr>\n<tr><td>11</td><td>ABA 문제를 면접에서 짧게 예로 들면 어떻게 설명하나요?</td><td>값이 A라서 안전하다고 봤지만 중간에 A-B-A로 바뀌어 참조 의미가 달라진 경우입니다.</td></tr>\n<tr><td>12</td><td>thread pool starvation을 실제 서비스에서 어떻게 탐지하고 완화하나요?</td><td>active thread, queue length, pool wait, thread dump를 보고 blocking 작업 분리와 timeout을 둡니다.</td></tr>\n</table>\n<div class=\"callout risk\"><span class=\"co-label\">답변 기준</span><p>각 답변은 “정의 → 발생 조건 → 관측 지표 → 완화책 → trade-off” 순서로 말하면 키워드 나열을 넘어섭니다.</p></div>\n</section>\n\n<section id=\"cs-q14\">\n<div class=\"ch-head\"><span class=\"ch-code\">CS-14</span><h2>CS 개념 인과관계</h2></div>\n<p class=\"lede\">CS 답변은 용어 정의보다 “왜 그 현상이 생기는지”를 설명할 때 깊어집니다. 면접관이 보고 싶은 것은 Big-O, thread, TCP 같은 단어 자체가 아니라 그 개념으로 실제 성능과 장애를 분해하는 사고입니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">CS CAUSAL MODEL</span>입력 크기가 커지면 알고리즘 비용이 늘고, 비용이 CPU 계산인지 I/O 대기인지에 따라 해결책이 달라집니다. thread가 많아지면 병렬성이 늘 수 있지만 context switching과 lock 경합이 늘어 tail latency를 키울 수 있습니다. TCP 연결이 새로 열리면 handshake와 congestion window 때문에 첫 요청이 느릴 수 있고, keep-alive를 쓰면 그 비용은 줄지만 connection leak과 FD 고갈을 관리해야 합니다. 좋은 답변은 한 개념을 다른 계층의 증상과 연결합니다.</div>\n<table>\n<tr><th>개념</th><th>원인</th><th>결과</th><th>면접에서 말할 문장</th></tr>\n<tr><td>Big-O</td><td>입력 크기 증가에 따라 반복 횟수나 탐색 공간이 커진다</td><td>작은 데이터에서는 괜찮던 코드가 대량 데이터에서 급격히 느려진다</td><td>“복잡도는 ms 예측이 아니라 증가율 판단이고, 실제로는 I/O와 호출 빈도를 함께 봅니다.”</td></tr>\n<tr><td>context switching</td><td>thread가 너무 많거나 blocking 대기가 많아 scheduler가 자주 실행 대상을 바꾼다</td><td>CPU가 실제 업무보다 전환과 cache miss에 시간을 쓴다</td><td>“thread를 늘리는 것은 항상 처리량 증가가 아니고 pool wait와 runnable thread 수를 함께 봅니다.”</td></tr>\n<tr><td>race condition</td><td>읽기-수정-쓰기 사이에 다른 실행 흐름이 끼어든다</td><td>테스트에서는 가끔만 실패하고 운영에서 값이 꼬인다</td><td>“lock 이름보다 어떤 invariant가 어떤 interleaving에서 깨지는지 먼저 설명합니다.”</td></tr>\n<tr><td>TCP/TLS</td><td>새 연결에는 handshake, 인증서 검증, congestion warm-up이 필요하다</td><td>첫 요청이나 connection churn이 p95/p99를 악화시킨다</td><td>“느린 API를 보면 application time뿐 아니라 DNS, TCP, TLS, server queue를 분리합니다.”</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">암기 답변 교정</span>\n<p>“프로세스는 자원 할당 단위, 스레드는 실행 단위”에서 멈추면 암기입니다. “그래서 thread는 메모리를 공유해 빠르지만 race condition이 생기고, process는 격리가 강해 장애 전파는 줄지만 IPC 비용이 듭니다”까지 이어져야 합니다.</p>\n</div>\n</section>\n\n<section id=\"doc-dbdeep\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>DB 심화 면접</h2></div>\n</section>\n\n<section id=\"dbdeep-q1\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-01</span><h2>Q. DB 심화 질문은 어떤 프레임으로 답하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>DB 답변은 기능 구현보다 데이터 정합성 요구, 읽기/쓰기 패턴, 동시성, 복구, 운영 변경 위험을 함께 설명해야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>DB 심화 답변은 기능명보다 정합성, 성능, 운영 위험을 동시에 보는 프레임이 중요합니다. 같은 인덱스도 읽기 성능, 쓰기 비용, 락, 배포 위험이 함께 있습니다. 면접에서는 쿼리 하나를 고치는 기술보다 장애와 변경을 견디는 판단 기준을 보여줘야 합니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">먼저 데이터 정합성 요구와 읽기/쓰기 패턴을 확인합니다. 그 다음 transaction 경계, isolation level, lock, index, query plan을 근거로 설계하고, 마지막으로 백업·복제·마이그레이션·복구 훈련 같은 운영 리스크를 봅니다.</div>\n<h3>90초 답변</h3>\n<p>예를 들어 주문 상태 변경은 단순 update가 아니라 중복 요청, lost update, 외부 결제 API timeout, 상태 전이, audit log까지 봐야 합니다. 검색 API는 index와 pagination만이 아니라 cardinality, selectivity, sort 비용, stale read 허용 여부를 봅니다. 면접에서는 “트랜잭션을 겁니다”보다 어떤 anomaly를 막고 어떤 비용을 감수하는지 말해야 합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>DB에서 가장 중요한 품질은?</td><td>정확성, 일관성, 복구 가능성, 성능, 운영 가능성의 균형입니다.</td></tr><tr><td>성능과 정합성이 충돌하면?</td><td>도메인 요구와 실패 비용을 기준으로 선택합니다.</td></tr><tr><td>실무 증거는?</td><td>EXPLAIN, slow query log, migration dry-run, backup restore drill을 말합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>DB 질문에서 도구나 ORM API만 말하면 얕습니다. 데이터가 깨지는 조건을 먼저 봐야 합니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q2\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-02</span><h2>Q. MVCC는 무엇이고 왜 필요한가요?</h2></div>\n<h3>핵심 개념</h3>\n<p>MVCC는 row version을 관리해 reader와 writer가 서로를 덜 막으면서 일관된 snapshot을 보게 하는 동시성 제어 방식입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>MVCC는 독자가 쓰기를 막고 쓰기가 독자를 막는 상황을 줄이기 위해 row version을 유지하는 모델입니다. transaction은 자기 snapshot을 보고, DB는 오래된 version을 일정 기간 보존합니다. 오래 열린 transaction은 vacuum이나 undo 정리를 막아 bloat와 성능 문제를 만들 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">MVCC는 update가 기존 row를 덮어쓰는 대신 새 version을 만들고, transaction은 자신의 snapshot에서 보이는 version을 읽습니다. 그래서 읽기가 쓰기를 항상 막지 않아 동시성이 좋아집니다. 대신 오래 열린 transaction이 있으면 오래된 version 정리가 늦어져 bloat나 vacuum 문제가 생길 수 있습니다.</div>\n<h3>90초 답변</h3>\n<p>PostgreSQL 같은 MVCC DB에서는 각 transaction이 볼 수 있는 row version이 정해져 있습니다. Read Committed에서는 statement마다 snapshot이 바뀌고, Repeatable Read에서는 transaction 시작 시점 snapshot이 유지됩니다. MVCC는 lock을 없애는 것이 아니라 읽기/쓰기 충돌을 줄이는 방식이며, 쓰기-쓰기 충돌이나 unique constraint, row lock은 여전히 중요합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>vacuum은 왜 필요한가요?</td><td>더 이상 보이지 않는 오래된 row version을 정리해 bloat를 줄입니다.</td></tr><tr><td>long transaction 문제는?</td><td>old version 정리를 막아 bloat, xid wraparound, replication lag 위험을 키웁니다.</td></tr><tr><td>MVCC면 lock이 필요 없나요?</td><td>아닙니다. 쓰기 충돌, DDL, FK, unique check에는 lock이 필요합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>autovacuum, dead tuple, long running transaction, lock wait를 실제 지표로 언급하면 깊이가 생깁니다.</p>\n</section>\n\n<section id=\"dbdeep-q3\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-03</span><h2>Q. 트랜잭션 격리 수준은 어떻게 선택하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>격리 수준은 transaction들이 서로의 중간 상태나 변경을 어느 정도 볼 수 있는지 정하는 정책입니다. 높을수록 anomaly는 줄지만 충돌과 retry 비용이 커질 수 있습니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>격리 수준은 anomaly를 얼마나 허용할지의 선택입니다. dirty read, non-repeatable read, phantom, write skew 같은 현상 중 도메인이 허용하지 않는 것이 무엇인지 먼저 정해야 합니다. DB마다 같은 이름의 isolation도 구현이 다를 수 있으므로 PostgreSQL, MySQL 차이를 분리해 말하는 편이 정확합니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">Read Committed는 statement마다 commit된 최신 데이터를 보고, Repeatable Read는 transaction 동안 같은 snapshot을 유지합니다. Serializable은 직렬 실행과 같은 결과를 목표로 하지만 serialization failure에 대한 retry 설계가 필요합니다. 선택 기준은 막아야 하는 anomaly와 성능 비용입니다.</div>\n<h3>90초 답변</h3>\n<p>실무에서는 isolation level만 올리는 것이 답이 아닐 수 있습니다. 재고 차감은 조건부 update나 row lock이 더 명확할 수 있고, 편집 충돌은 optimistic locking이 사용자 경험에 맞을 수 있습니다. Serializable을 쓰면 더 안전해 보이지만 충돌 시 재시도 로직과 idempotency가 없으면 장애로 이어질 수 있습니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>non-repeatable read는?</td><td>같은 transaction에서 같은 row를 다시 읽었을 때 값이 달라지는 현상입니다.</td></tr><tr><td>phantom read는?</td><td>조건에 맞는 row 집합이 transaction 중 달라지는 현상입니다.</td></tr><tr><td>Serializable 실패는?</td><td>DB가 직렬화 불가능한 실행을 감지하면 transaction retry가 필요합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“중요하면 Serializable을 씁니다”는 반쪽 답변입니다. retry와 성능 비용까지 말해야 합니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q4\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-04</span><h2>Q. 락과 deadlock은 어떻게 다루나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>락은 동시 변경의 정합성을 지키기 위한 제어이고, deadlock은 transaction들이 서로가 가진 락을 기다리며 진행하지 못하는 상태입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>락은 데이터 정합성을 지키지만 대기와 deadlock이라는 비용을 만듭니다. row lock, gap lock, table lock, metadata lock은 발생 조건과 영향 범위가 다릅니다. deadlock은 단순 오류가 아니라 DB가 교착을 감지해 한쪽 transaction을 희생시킨 것이므로 retry와 lock 순서 통일이 필요합니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">락 문제는 긴 transaction, 누락 인덱스, 일관되지 않은 락 획득 순서, transaction 안의 외부 API 호출에서 자주 생깁니다. deadlock을 줄이려면 같은 순서로 row를 잠그고, transaction을 짧게 유지하고, lock timeout과 retry를 설계합니다.</div>\n<h3>90초 답변</h3>\n<p>lock wait가 길면 먼저 어떤 query가 어떤 lock을 잡고 있는지 봅니다. 인덱스가 없어 더 많은 row를 스캔하며 잠그는 경우, 사용자 입력을 기다리거나 외부 API를 호출하는 동안 transaction이 열려 있는 경우가 흔합니다. deadlock은 DB가 하나를 abort할 수 있으므로 애플리케이션은 안전한 retry와 idempotency를 갖춰야 합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>SELECT FOR UPDATE는 언제?</td><td>읽은 row를 이후 update할 것이고 경쟁 변경을 막아야 할 때 씁니다.</td></tr><tr><td>lock timeout은 왜?</td><td>무한 대기를 막고 장애를 빨리 감지하기 위해 둡니다.</td></tr><tr><td>외부 API를 transaction 안에서 호출하면?</td><td>transaction 시간이 길어져 lock wait와 deadlock 위험이 커집니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>lock table, slow query, transaction duration, deadlock log를 확인한 경험을 말합니다.</p>\n</section>\n\n<section id=\"dbdeep-q5\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-05</span><h2>Q. lost update는 왜 생기고 어떻게 막나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>lost update는 두 transaction이 같은 값을 읽고 각각 수정해 한쪽 변경이 사라지는 동시성 문제입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>lost update는 두 transaction이 같은 값을 읽고 각각 수정했는데 나중 commit이 앞선 변경을 덮어쓰는 문제입니다. version column, 조건부 update, row lock, serializable isolation 등으로 막을 수 있습니다. 어떤 방법이든 충돌 감지 후 사용자나 시스템이 어떻게 재시도할지 정해야 합니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">lost update는 사용자가 같은 데이터를 동시에 수정할 때 자주 생깁니다. 해결은 version column 기반 optimistic locking, row lock 기반 pessimistic locking, 조건부 atomic update, isolation level 조정 중 요구사항에 맞게 선택합니다.</div>\n<h3>90초 답변</h3>\n<p>문서 편집처럼 충돌이 드문 작업은 optimistic locking이 적합합니다. update where id=? and version=?로 갱신하고 영향 row가 0이면 충돌을 알려 최신 데이터를 다시 보여줍니다. 재고 차감처럼 경쟁이 높은 작업은 update stock = stock - 1 where stock &gt; 0 같은 조건부 update나 row lock을 검토합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>optimistic lock의 UX는?</td><td>충돌 시 최신 데이터와 내 변경을 비교해 재시도하게 합니다.</td></tr><tr><td>pessimistic lock 단점은?</td><td>대기와 deadlock, throughput 감소가 생길 수 있습니다.</td></tr><tr><td>재고 차감은?</td><td>조건부 update, unique constraint, idempotency를 함께 봅니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“트랜잭션이면 됩니다”로는 부족합니다. 어떤 격리 수준에서 어떤 update가 어떻게 충돌하는지 말해야 합니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q6\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-06</span><h2>Q. 느린 쿼리는 어떤 순서로 분석하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>느린 쿼리 대응은 감으로 인덱스를 추가하는 일이 아니라 실제 실행 계획, row 수 추정, I/O, sort, join 비용을 확인하는 과정입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>느린 쿼리 분석은 실행 계획의 한 줄을 읽는 일이 아니라 planner의 예상과 실제 실행의 차이를 보는 일입니다. estimated rows와 actual rows가 크게 다르면 통계나 데이터 분포 문제가 있을 수 있습니다. sort, hash, nested loop, buffer read, lock wait를 함께 봐야 원인을 정확히 좁힙니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">먼저 재현 가능한 쿼리와 파라미터를 확보하고 EXPLAIN ANALYZE로 실제 실행 계획을 봅니다. estimated rows와 actual rows 차이, seq scan이 적절한지, join 방식, sort/hash 메모리, index 사용 여부를 확인합니다. 그 다음 인덱스, 쿼리 구조, 통계, pagination 방식을 조정합니다.</div>\n<h3>90초 답변</h3>\n<p>Seq Scan은 항상 나쁜 것이 아닙니다. 작은 테이블이나 selectivity가 낮은 조건에서는 합리적일 수 있습니다. 오히려 planner가 row 수를 크게 잘못 예측하면 잘못된 join 순서나 nested loop 폭증이 생깁니다. offset pagination은 뒤 페이지로 갈수록 비용이 커질 수 있어 keyset pagination을 검토합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>estimated와 actual 차이가 크면?</td><td>통계 갱신, 컬럼 상관관계, skew, extended statistics를 봅니다.</td></tr><tr><td>index를 추가하면 항상 빨라지나요?</td><td>읽기는 빨라질 수 있지만 write 비용, 저장 공간, planner 선택 문제가 생깁니다.</td></tr><tr><td>ORDER BY가 느리면?</td><td>정렬 메모리, 인덱스 순서, limit, keyset pagination을 봅니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>실제 plan의 rows, loops, buffers, sort method를 보고 판단했다는 식으로 말하면 신뢰도가 높습니다.</p>\n</section>\n\n<section id=\"dbdeep-q7\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-07</span><h2>Q. 인덱스는 어떻게 설계하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>인덱스는 자주 쓰는 WHERE, JOIN, ORDER BY 패턴을 빠르게 하지만 write 비용과 저장 공간을 늘립니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>인덱스 설계는 where 절 컬럼을 모두 넣는 작업이 아닙니다. equality, range, order by, covering 여부, selectivity, update 빈도를 고려해 컬럼 순서와 포함 범위를 정합니다. partial index나 expression index는 강력하지만 쿼리 조건이 정확히 맞아야 효과가 납니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">인덱스는 쿼리 패턴과 cardinality를 보고 설계합니다. equality 조건, range 조건, sort 조건의 순서를 보고 composite index 컬럼 순서를 정하고, active row만 자주 조회하면 partial index, projection이 제한되면 covering index를 검토합니다.</div>\n<h3>90초 답변</h3>\n<p>복합 인덱스는 왼쪽 prefix와 range 조건 이후 활용도를 이해해야 합니다. 예를 들어 tenant_id, status, created_at 조건이 반복되면 tenant_id와 status 같은 equality 조건을 앞에 두고 created_at range/order를 뒤에 둘 수 있습니다. 하지만 모든 조합에 인덱스를 만들면 write와 vacuum 비용이 커집니다. 실제 workload와 slow query 기준으로 관리해야 합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>covering index는?</td><td>필요 컬럼을 인덱스에서 충족해 table lookup을 줄이는 전략입니다.</td></tr><tr><td>partial index는?</td><td>deleted_at is null 같은 자주 쓰는 subset에만 인덱스를 만들어 크기를 줄입니다.</td></tr><tr><td>인덱스가 안 타면?</td><td>조건식, 타입 캐스팅, 함수 사용, selectivity, 통계, predicate 일치를 확인합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“자주 검색하는 컬럼에 인덱스”는 너무 얕습니다. 복합 조건, 정렬, 카디널리티, write 비용까지 봐야 합니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q8\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-08</span><h2>Q. 트랜잭션 경계는 어떻게 잡나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>트랜잭션 경계는 함께 성공하거나 함께 실패해야 하는 비즈니스 정합성 단위입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>트랜잭션 경계는 비즈니스 불변식을 지키는 최소 단위여야 합니다. 너무 짧으면 중간 상태가 노출되고, 너무 길면 lock과 connection을 오래 잡습니다. 외부 API 호출, 파일 처리, 사용자 입력 대기 같은 느린 작업을 transaction 안에 넣으면 장애가 DB로 전파됩니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">트랜잭션은 DB 작업을 많이 묶는 것이 아니라 정합성 단위로 묶어야 합니다. 외부 API 호출, 사용자 입력 대기, 긴 batch 처리는 transaction 밖으로 빼거나 outbox, saga, idempotency 같은 패턴을 검토합니다.</div>\n<h3>90초 답변</h3>\n<p>예를 들어 주문 생성과 결제 요청은 하나의 DB transaction으로 외부 API까지 묶기 어렵습니다. DB에는 주문 pending과 outbox event를 같은 transaction으로 저장하고, 별도 worker가 결제 요청을 처리한 뒤 상태를 전이할 수 있습니다. 이렇게 하면 DB 정합성과 외부 시스템 실패를 분리할 수 있습니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>긴 transaction 문제는?</td><td>lock 유지, MVCC bloat, replication lag, deadlock 위험이 커집니다.</td></tr><tr><td>외부 API와 DB를 원자적으로 묶을 수 있나요?</td><td>일반적으로 어렵고 outbox/saga/idempotency로 보완합니다.</td></tr><tr><td>rollback은 언제 되나요?</td><td>DB 작업은 되돌릴 수 있지만 외부 side effect는 별도 보상이나 상태 관리가 필요합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>transaction 안에서 외부 호출을 제거하거나 outbox로 분리한 설계를 말하면 강합니다.</p>\n</section>\n\n<section id=\"dbdeep-q9\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-09</span><h2>Q. Connection Pool은 왜 필요하고 어떤 문제가 생기나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>Connection Pool은 DB connection 생성 비용을 줄이고 동시 접근을 제어하지만, 설정을 잘못하면 DB를 과부하시키거나 app request를 대기시킵니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Connection Pool은 DB connection 생성 비용을 줄이고 동시 접근 수를 제한하는 backpressure 장치입니다. pool이 너무 작으면 대기가 늘고, 너무 크면 DB가 context switching과 lock 경합으로 무너질 수 있습니다. leak, slow query, 긴 transaction은 pool 고갈로 먼저 드러나는 경우가 많습니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">DB connection은 생성 비용이 크고 DB가 처리할 수 있는 수가 제한적이므로 pool로 재사용합니다. 하지만 app instance가 늘 때 pool size도 곱해져 DB max connection을 초과할 수 있습니다. pool size, timeout, transaction duration, slow query를 함께 봐야 합니다.</div>\n<h3>90초 답변</h3>\n<p>connection pool 문제는 트래픽 증가, autoscaling, slow query와 같이 나타납니다. DB connection이 부족하면 app은 pool 대기 시간이 늘고, timeout이 발생하며, retry가 더 큰 부하를 만들 수 있습니다. 해결은 pool size를 무작정 키우는 것이 아니라 query 최적화, transaction 단축, read/write 분리, pooler 사용, backpressure를 함께 검토하는 것입니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>pool size는 어떻게 정하나요?</td><td>DB max connection, app instance 수, query duration, CPU/I/O 병목을 기준으로 조정합니다.</td></tr><tr><td>connection leak은?</td><td>반납 누락, transaction 미종료, 예외 경로를 확인합니다.</td></tr><tr><td>retry 폭주는?</td><td>timeout, exponential backoff, circuit breaker, request shedding을 봅니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>DB가 느리다고 pool만 키우면 병목을 DB로 밀어 넣어 장애를 키울 수 있습니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q10\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-10</span><h2>Q. WAL과 replication은 어떤 역할을 하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>WAL은 변경 내용을 데이터 파일보다 먼저 로그에 기록해 crash recovery와 replication의 기반이 됩니다. replication은 가용성과 읽기 확장을 돕지만 복구와 백업을 대체하지 않습니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>WAL은 변경을 먼저 순차 로그로 남겨 crash recovery와 replication의 기반을 제공합니다. replication은 읽기 확장과 장애 대응에 유리하지만 lag가 있으면 stale read와 read-your-writes 문제가 생깁니다. 복제본은 백업이 아니며, 잘못 삭제한 데이터도 빠르게 복제될 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">WAL은 DB 변경을 먼저 로그로 남겨 장애 후 복구할 수 있게 합니다. replica는 WAL을 받아 primary 변경을 따라가며 읽기 부하 분산이나 failover에 쓰입니다. 하지만 replication lag가 있으면 replica read가 stale할 수 있고, 논리적 삭제나 잘못된 update는 replica에도 전파됩니다.</div>\n<h3>90초 답변</h3>\n<p>replication은 고가용성 도구이지 과거 시점 복구 도구가 아닙니다. primary에서 잘못 삭제한 데이터는 replica에도 반영될 수 있으므로 backup과 PITR이 필요합니다. read replica를 사용할 때는 read-after-write 요구가 있는 기능을 primary에서 읽거나 session consistency를 보장해야 합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>replication lag 원인은?</td><td>write 폭증, long query, network, replica 성능, WAL apply 지연을 봅니다.</td></tr><tr><td>read replica를 언제 쓰나요?</td><td>읽기 부하 분산에 쓰지만 stale data 허용 여부를 확인합니다.</td></tr><tr><td>failover 후 주의점은?</td><td>DNS/endpoint, connection 재시도, split brain, 데이터 손실 가능성을 봅니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>replica lag metric, PITR, failover drill, read-after-write 이슈를 설명할 수 있으면 좋습니다.</p>\n</section>\n\n<section id=\"dbdeep-q11\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-11</span><h2>Q. 백업과 복구는 어떻게 검증하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>백업은 존재하는 것만으로 충분하지 않습니다. 실제 복구에 걸리는 시간, 복구된 데이터의 정합성, 운영 전환 절차를 검증해야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>백업은 존재한다는 사실보다 복구해봤다는 증거가 중요합니다. RPO/RTO 목표에 맞게 full/incremental backup, PITR, restore drill을 설계해야 합니다. 백업 파일이 있어도 암호화 키, 권한, 절차, 복구 시간 검증이 없으면 실제 사고에서 쓸 수 없습니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">backup은 과거 시점 복구와 실수 복구를 위해 필요하고, replication은 가용성을 위한 것입니다. RPO와 RTO를 정하고, 정기적으로 restore drill을 수행해 백업 파일이 실제로 복구되는지, 권한과 secret, app config까지 맞는지 확인해야 합니다.</div>\n<h3>90초 답변</h3>\n<p>복구 훈련에서는 DB만 띄우는 것으로 끝나면 안 됩니다. 특정 시점으로 복구한 뒤 schema version, application compatibility, user count, checksum, 핵심 쿼리, 권한, connection string 전환까지 확인해야 합니다. 개인정보와 보안 요구가 있다면 백업 암호화, 접근 통제, 보관 기간, 삭제 정책도 필요합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>RPO/RTO 차이는?</td><td>허용 가능한 데이터 손실량과 복구 목표 시간입니다.</td></tr><tr><td>백업이 실패했는지 어떻게 아나요?</td><td>백업 job success뿐 아니라 restore drill과 alert가 필요합니다.</td></tr><tr><td>테스트 환경 복구는?</td><td>민감정보 마스킹과 접근 제한이 필요합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“자동 백업이 켜져 있습니다”는 충분한 답변이 아닙니다. 복구 검증이 핵심입니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q12\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-12</span><h2>Q. 무중단 DB migration은 어떻게 설계하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>무중단 migration은 구버전과 신버전 애플리케이션이 동시에 동작할 수 있도록 schema 변경을 backward compatible하게 나누는 방식입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>무중단 migration은 schema 변경과 애플리케이션 배포가 동시에 깨지지 않도록 시간을 나누는 작업입니다. expand 단계에서 새 구조를 추가하고 양쪽 코드가 호환되게 만든 뒤, backfill과 dual read/write를 거쳐 contract 단계에서 오래된 구조를 제거합니다. lock을 유발하는 DDL과 backfill 부하를 별도로 관리해야 합니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">expand-contract 방식으로 진행합니다. 먼저 nullable column이나 새 table처럼 호환되는 schema를 추가하고, 앱이 양쪽 schema를 읽고 쓸 수 있게 배포합니다. 그 다음 backfill과 검증을 거쳐 not null/constraint 적용, old column 제거를 마지막에 합니다. 큰 index는 가능하면 concurrently 생성합니다.</div>\n<h3>90초 답변</h3>\n<p>위험한 변경은 column rename, type 변경, not null 추가, default backfill, 대형 table index 생성, FK validation입니다. 한 번에 바꾸면 lock과 구버전 앱 호환성 문제가 생깁니다. 따라서 migration은 배포 순서와 함께 설계해야 합니다. backfill은 batch로 나누고, 진행률과 lock wait, replication lag를 관찰합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>NOT NULL 추가는?</td><td>nullable 추가, backfill, check constraint validate, set not null 순서로 나눕니다.</td></tr><tr><td>column rename은?</td><td>새 컬럼 추가, dual write, read fallback, 전환, old column 제거로 나눕니다.</td></tr><tr><td>migration rollback은?</td><td>파괴적 변경은 rollback이 어려우므로 호환 단계와 feature flag가 중요합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>dry-run, lock timeout, batch backfill, migration version, rollback plan을 말하면 운영 경험이 드러납니다.</p>\n</section>\n\n<section id=\"dbdeep-q13\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-13</span><h2>핵심 질문 35선과 답변 훈련</h2></div>\n<p class=\"lede\">DB 심화 면접은 “데이터가 언제 깨질 수 있는가”와 “운영 중 어떻게 바꿀 것인가”를 묻습니다.</p>\n<table>\n<tr><th>축</th><th>핵심 질문</th><th>확장 포인트</th></tr>\n<tr><td>동시성</td><td>MVCC, isolation level, lock, deadlock, lost update, optimistic/pessimistic lock</td><td>막아야 할 anomaly와 비용</td></tr>\n<tr><td>성능</td><td>EXPLAIN ANALYZE, selectivity, cardinality, join, sort, pagination, slow query</td><td>실행 계획 근거와 실제 row 수</td></tr>\n<tr><td>인덱스</td><td>composite, covering, partial, unique, FK index, write overhead</td><td>쿼리 패턴과 운영 비용</td></tr>\n<tr><td>운영</td><td>connection pool, replication lag, backup, PITR, restore drill, failover</td><td>복구 가능성과 stale read</td></tr>\n<tr><td>변경</td><td>zero-downtime migration, backfill, lock, concurrent index, expand-contract</td><td>배포 순서와 rollback 가능성</td></tr>\n</table>\n<h3>구체 질문 12선</h3>\n<table>\n<tr><th>번호</th><th>구체 질문</th><th>답변 방향</th></tr>\n<tr><td>1</td><td>Read Committed에서 같은 transaction 안의 두 SELECT 결과가 달라질 수 있는 이유는 무엇인가요?</td><td>statement마다 snapshot이 새로 잡히는 구현과 non-repeatable read를 설명합니다.</td></tr>\n<tr><td>2</td><td>PostgreSQL에서 long transaction이 vacuum을 방해하면 어떤 운영 증상이 생기나요?</td><td>dead tuple 증가, table/index bloat, xid wraparound 위험, replication lag를 연결합니다.</td></tr>\n<tr><td>3</td><td>InnoDB Repeatable Read에서 snapshot read와 locking read는 어떻게 다르게 동작하나요?</td><td>read view 기반 consistent read와 current read/next-key lock을 구분합니다.</td></tr>\n<tr><td>4</td><td>복합 인덱스 (tenant_id, status, created_at)가 있을 때 status만 조건으로 검색하면 왜 활용도가 낮나요?</td><td>B-tree leftmost prefix 원칙과 leading column 누락을 설명합니다.</td></tr>\n<tr><td>5</td><td>index-only scan인데도 heap/table 접근이 생길 수 있는 이유는 무엇인가요?</td><td>visibility 확인, PostgreSQL visibility map, 커버링 컬럼 부족을 말합니다.</td></tr>\n<tr><td>6</td><td>EXPLAIN ANALYZE에서 estimated rows와 actual rows가 크게 다르면 무엇을 의심하나요?</td><td>통계 부정확, 데이터 skew, 컬럼 상관관계, parameter 분포를 봅니다.</td></tr>\n<tr><td>7</td><td>loops가 큰 nested loop 계획은 언제 문제가 되나요?</td><td>inner scan 반복 횟수와 실제 rows 곱으로 비용이 폭증하는지 확인합니다.</td></tr>\n<tr><td>8</td><td>buffers hit와 read를 보고 쿼리 병목을 어떻게 구분하나요?</td><td>cache hit 중심인지 disk read 중심인지, warm cache 착시가 있는지 봅니다.</td></tr>\n<tr><td>9</td><td>인덱스를 추가했는데 write 성능과 vacuum 비용이 나빠질 수 있는 이유는 무엇인가요?</td><td>모든 insert/update/delete가 인덱스 유지 비용과 bloat를 만든다고 설명합니다.</td></tr>\n<tr><td>10</td><td>offset pagination이 뒤 페이지에서 느려지는 이유와 대안은 무엇인가요?</td><td>앞 row를 버리는 scan 비용과 keyset pagination 조건을 비교합니다.</td></tr>\n<tr><td>11</td><td>Serializable을 도입했는데 장애가 늘어난다면 애플리케이션에서 무엇이 빠졌을 가능성이 큰가요?</td><td>serialization failure retry, idempotency, timeout budget 설계를 봅니다.</td></tr>\n<tr><td>12</td><td>무중단 migration에서 NOT NULL 제약을 한 번에 추가하면 어떤 위험이 있나요?</td><td>table scan/lock, 기존 row 검증, 구버전 앱 호환성 문제를 나눠 말합니다.</td></tr>\n</table>\n<div class=\"callout risk\"><span class=\"co-label\">압박 꼬리질문</span><p>“트랜잭션인데 왜 lost update가 나나요?”, “Seq Scan은 항상 문제인가요?”, “replica가 있는데 백업이 왜 필요하죠?”, “컬럼 rename을 무중단으로 어떻게 하나요?”에 답할 수 있어야 합니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q14\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-14</span><h2>MVCC INDEX PLAN DEEP DIVE</h2></div>\n<p class=\"lede\">DB 심화 면접에서 강한 답변은 MVCC 내부, 인덱스 접근 조건, 실행 계획의 실제 수치를 한 문장 안에서 연결합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">MVCC INDEX PLAN DEEP DIVE</span>\nPostgreSQL은 row version마다 xmin/xmax로 생성·삭제 transaction 정보를 기록하고 snapshot이 어떤 version을 볼 수 있는지 판단합니다. InnoDB는 read view와 undo log를 통해 consistent read를 제공하며, 오래 열린 transaction은 undo 정리를 지연시킵니다. 성능 분석에서는 btree leftmost prefix, index-only scan 가능성, EXPLAIN ANALYZE의 rows/loops/buffers를 함께 확인해야 합니다.\n</div>\n<h3>MVCC 내부 비교</h3>\n<table>\n<tr><th>항목</th><th>PostgreSQL</th><th>InnoDB</th><th>면접 포인트</th></tr>\n<tr><td>버전 식별</td><td>tuple의 xmin/xmax가 생성·삭제 transaction을 나타냅니다.</td><td>record와 undo log, transaction id를 기반으로 과거 버전을 재구성합니다.</td><td>보이는 row는 “최신 row”가 아니라 snapshot 기준으로 visible한 version입니다.</td></tr>\n<tr><td>Snapshot</td><td>활성 transaction 목록과 xmin 경계를 기준으로 visibility를 판단합니다.</td><td>read view가 low/high watermark와 active transaction을 기준으로 판단합니다.</td><td>격리 수준에 따라 snapshot 생성 시점이 달라집니다.</td></tr>\n<tr><td>정리 지연</td><td>long transaction이 vacuum과 dead tuple 정리를 막습니다.</td><td>long transaction이 undo log purge를 지연시킵니다.</td><td>오래 열린 읽기 transaction도 운영 비용을 만들 수 있습니다.</td></tr>\n<tr><td>Lock 관계</td><td>MVCC가 reader/writer 충돌을 줄이지만 row lock과 predicate 문제는 남습니다.</td><td>consistent read와 locking read가 다르고 gap/next-key lock이 중요합니다.</td><td>“MVCC면 lock이 없다”는 오답을 피해야 합니다.</td></tr>\n</table>\n<h3>인덱스와 실행 계획 해석</h3>\n<p>B-tree 복합 인덱스는 leftmost prefix가 중요합니다. <code>(tenant_id, status, created_at)</code> 인덱스는 tenant_id 단독, tenant_id+status, tenant_id+status+created_at 조건에는 잘 맞지만 status만 있는 조건에는 일반적으로 효율이 낮습니다. range 조건이 등장한 뒤에는 뒤 컬럼의 filtering/order 활용도가 제한될 수 있으므로 equality 조건, range 조건, ORDER BY를 순서대로 설명해야 합니다.</p>\n<p>index-only scan은 인덱스만 읽는다는 뜻처럼 보이지만, PostgreSQL에서는 visibility map이 충분히 표시되어 있어야 heap visibility 확인을 줄일 수 있습니다. 필요한 컬럼이 모두 인덱스에 있어도 최근 변경이 많거나 visibility map이 깨져 있으면 heap fetch가 생길 수 있습니다. 그래서 covering index 설계와 vacuum 상태를 함께 봐야 합니다.</p>\n<table>\n<tr><th>EXPLAIN ANALYZE 항목</th><th>읽는 방법</th><th>위험 신호</th></tr>\n<tr><td>rows</td><td>planner 예상 rows와 actual rows를 비교합니다.</td><td>차이가 크면 통계, skew, 조건 상관관계 문제가 있을 수 있습니다.</td></tr>\n<tr><td>loops</td><td>plan node가 반복 실행된 횟수입니다.</td><td>inner node loops가 크면 nested loop가 실제로 폭증했는지 봅니다.</td></tr>\n<tr><td>buffers</td><td>shared hit/read/dirtied/written으로 cache와 I/O를 봅니다.</td><td>read가 크면 disk I/O, hit만 크면 CPU/반복 scan 병목일 수 있습니다.</td></tr>\n<tr><td>actual time</td><td>각 node의 시작/종료 실제 시간을 봅니다.</td><td>한 node보다 반복 누적 시간이 병목일 수 있어 rows*loops로 봅니다.</td></tr>\n</table>\n<div class=\"callout warn\"><span class=\"co-label\">답변 주의</span><p>“인덱스를 타서 빠릅니다”는 충분하지 않습니다. 어떤 prefix로 접근했고, index-only scan이 실제 heap fetch를 줄였는지, rows/loops/buffers가 예측과 맞는지를 함께 말해야 합니다.</p></div>\n</section>\n\n<section id=\"dbdeep-q15\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-15</span><h2>DB 개념 인과관계</h2></div>\n<p class=\"lede\">DB 심화 답변은 MVCC, index, isolation을 각각 외우는 것이 아니라 동시 읽기와 쓰기를 어떻게 동시에 허용하면서도 어떤 이상 현상이 남는가를 설명해야 합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">DB CAUSAL MODEL</span>MVCC는 쓰기 중인 row를 읽기 위해 기다리게 만들지 않고, transaction snapshot이 볼 수 있는 version을 선택하게 합니다. 그래서 읽기 동시성은 좋아지지만 오래 열린 transaction은 vacuum을 막고 dead tuple을 쌓아 bloat를 만들 수 있습니다. 인덱스는 탐색 범위를 줄이지만 쓰기마다 인덱스도 갱신해야 하므로 write amplification을 만듭니다. isolation level은 동시성 이상 현상을 줄이지만 높일수록 abort, lock, retry 비용이 커집니다. 따라서 “Serializable이 가장 안전합니다”가 아니라 어떤 불변식을 보호해야 하는지부터 말해야 합니다.</div>\n<table>\n<tr><th>개념</th><th>문제가 생기는 원인</th><th>현상</th><th>선택 기준</th></tr>\n<tr><td>MVCC</td><td>row version과 snapshot이 오래 유지된다</td><td>vacuum 지연, bloat, 오래된 데이터 관측</td><td>transaction 길이, vacuum 지표, snapshot age를 본다</td></tr>\n<tr><td>복합 인덱스</td><td>쿼리의 equality/range/order 조건과 컬럼 순서가 맞지 않는다</td><td>index scan 후 filter, sort, full scan이 발생한다</td><td>선택도, 정렬, covering 여부, 쓰기 비용을 함께 본다</td></tr>\n<tr><td>isolation</td><td>동시 transaction이 같은 불변식을 다른 row나 range에서 깨뜨린다</td><td>lost update, write skew, phantom read</td><td>row lock, optimistic lock, constraint, Serializable 중 비용을 비교한다</td></tr>\n<tr><td>migration</td><td>schema 변경과 구버전 코드가 동시에 운영된다</td><td>lock, 실패한 배포, rollback 불가</td><td>expand-contract, backfill, dual-read/write, validation 순서를 둔다</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">면접 답변 전환</span>\n<p>“인덱스는 조회를 빠르게 합니다”에서 끝내지 말고 “인덱스는 탐색 범위를 줄이지만 insert/update/delete 때 유지 비용이 생기고, 낮은 선택도나 조건 순서가 맞지 않으면 효과가 작습니다. 그래서 실제 쿼리의 실행 계획에서 estimated rows와 actual rows, sort, buffer hit를 확인합니다”라고 설명합니다.</p>\n</div>\n</section>\n\n<section id=\"dbdeep-q16\">\n<div class=\"ch-head\"><span class=\"ch-code\">DBD-16</span><h2>실행계획 실전 해석: MVCC, 인덱스, 락을 함께 읽기</h2></div>\n<p class=\"lede\">DB 심화 면접에서 전문가처럼 보이려면 “인덱스를 탔습니다”가 아니라 실행 계획의 rows, loops, buffers, lock wait, MVCC visibility를 같은 현상으로 읽어야 합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">EXPERT DB PLAN CASE</span>시나리오는 <code>tenant_id</code>, <code>status</code>, <code>created_at</code> 조건으로 주문 목록을 조회하는 API가 뒤 페이지에서 느려지는 경우입니다. 초보 답변은 “복합 인덱스를 추가합니다”입니다. 전문가 답변은 먼저 쿼리의 목적을 나눕니다. tenant 범위가 강한지, status 선택도가 높은지, date range가 넓은지, ORDER BY가 created_at desc인지, offset pagination인지, 필요한 컬럼이 인덱스에 포함되는지 확인합니다. 그 뒤 실행계획에서 planner 예상 rows와 actual rows가 얼마나 다른지, sort가 발생하는지, heap fetch가 많은지, buffers read가 큰지 봅니다.</div>\n<h3>1. estimated rows와 actual rows</h3>\n<p>planner는 통계를 기반으로 어떤 plan이 싸다고 추정합니다. 하지만 tenant별 데이터 분포가 심하게 다르거나 status와 created_at이 강하게 상관되어 있으면 예상 rows가 틀릴 수 있습니다. 예상은 1,000 row인데 실제는 500,000 row라면 nested loop가 폭발하거나 잘못된 index가 선택될 수 있습니다. 이때 해결은 단순히 인덱스를 더 만드는 것이 아니라 <code>ANALYZE</code>, extended statistics, query rewrite, partial index, tenant별 partitioning 가능성까지 검토하는 것입니다.</p>\n<h3>2. Index scan이 항상 좋은 것은 아니다</h3>\n<p>Index scan은 필요한 row가 적을 때 강합니다. 하지만 선택도가 낮아 테이블 대부분을 읽어야 한다면 index를 따라 random access하는 비용이 sequential scan보다 클 수 있습니다. PostgreSQL의 index-only scan도 visibility map이 충분히 설정되어 있어야 heap fetch를 줄입니다. 최근 update가 많아 visibility 확인이 필요하면 인덱스에 컬럼이 다 있어도 heap을 읽게 됩니다. 따라서 “covering index라 빠르다”가 아니라 heap fetch와 buffers를 함께 봐야 합니다.</p>\n<h3>3. Offset pagination의 비용</h3>\n<p><code>OFFSET 100000 LIMIT 50</code>은 앞의 100,000개를 건너뛰어야 합니다. 사용자는 50개만 받지만 DB는 정렬된 후보를 많이 처리합니다. cursor/keyset pagination은 마지막으로 본 <code>created_at, id</code>를 기준으로 다음 범위를 좁히므로 뒤 페이지 비용이 안정적입니다. 다만 임의 페이지 이동이 어렵고 정렬 기준이 안정적이어야 합니다. 관리자 화면에서 “페이지 번호 이동”이 꼭 필요한지, 아니면 필터와 cursor 탐색으로 충분한지 제품 요구와 같이 판단해야 합니다.</p>\n<h3>4. MVCC와 오래 열린 transaction</h3>\n<p>MVCC는 reader와 writer 충돌을 줄이지만, 오래 열린 transaction은 오래된 row version 정리를 막습니다. PostgreSQL에서는 dead tuple이 쌓이고 vacuum이 지연되면 table bloat와 index bloat가 생깁니다. 이 상태에서는 같은 쿼리도 더 많은 page를 읽게 되어 buffers가 늘고 cache 효율이 떨어집니다. “쿼리는 그대로인데 점점 느려졌다”면 데이터 증가뿐 아니라 long transaction, autovacuum 지연, bloat를 의심해야 합니다.</p>\n<h3>5. 락과 격리 수준</h3>\n<p>실행 시간이 길어 보이는 쿼리가 실제로는 실행 중이 아니라 lock을 기다리고 있을 수 있습니다. row lock, relation lock, migration DDL lock, foreign key check가 대기 원인이 됩니다. Read Committed에서는 statement마다 snapshot이 달라질 수 있고, Repeatable Read에서는 transaction 동안 snapshot이 유지됩니다. Serializable은 더 강한 보장을 목표로 하지만 serialization failure가 발생할 수 있어 retry가 설계 일부가 됩니다. 격리 수준을 올리는 답변에는 반드시 retry, 사용자 안내, idempotency가 따라와야 합니다.</p>\n<h3>면접에서의 90초 답변</h3>\n<p>“저는 먼저 EXPLAIN ANALYZE에서 estimated rows와 actual rows 차이, loops, sort, buffers, heap fetch를 봅니다. index scan이 있어도 선택도가 낮거나 heap fetch가 많으면 느릴 수 있습니다. offset pagination이면 뒤 페이지 비용이 커지므로 keyset pagination을 검토하고, 통계가 틀리면 ANALYZE나 extended statistics를 봅니다. 동시에 lock wait와 long transaction, autovacuum 지연, bloat도 확인합니다. 격리 수준이나 락을 바꾸는 선택은 정합성 이상 현상을 막는 대신 abort와 retry 비용이 생기므로 도메인 불변식 기준으로 결정합니다.”</p>\n<div class=\"callout\">\n<span class=\"co-label\">전문가 기준</span>\n<p>DB 답변에서 중요한 것은 “인덱스 추가”가 아니라 왜 planner가 그 plan을 선택했고, 실제 실행에서 어디에 시간이 쌓였으며, 그 해결책이 읽기 성능·쓰기 비용·운영 변경 위험을 어떻게 바꾸는지 설명하는 것입니다.</p>\n</div>\n</section>\n\n<section id=\"doc-security\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>보안 심화 면접</h2></div>\n</section>\n\n<section id=\"security-q1\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-01</span><h2>Q. 보안 질문은 어떤 프레임으로 답하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>보안 답변은 취약점 이름보다 보호할 자산, 공격자가 조작할 수 있는 입력, 신뢰 경계, 서버 방어선, 탐지와 복구를 함께 설명해야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>보안 답변은 취약점 이름을 나열하는 것이 아니라 asset, actor, trust boundary, attack path, control을 연결하는 일입니다. 무엇을 지키는지와 누가 어떤 경로로 침해할 수 있는지 정의해야 방어선이 의미를 가집니다. UI 제어, API 인증, DB 제약, 로그는 서로 다른 방어층입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">먼저 보호할 자산과 신뢰 경계를 정의합니다. 그 다음 공격자가 바꿀 수 있는 입력을 식별하고, 서버 측 검증과 권한 확인을 설명합니다. 마지막으로 방어 우회 가능성, audit log, rate limit, alert, 테스트로 어떻게 검증할지 말합니다.</div>\n<h3>90초 답변</h3>\n<p>예를 들어 “파일 다운로드 API가 안전한가”라는 질문은 URL을 숨겼는지보다 현재 사용자가 해당 파일을 읽을 권한이 있는지, tenant scope가 맞는지, presigned URL 만료가 짧은지, 다운로드 로그가 남는지, 민감 파일이 cache되지 않는지까지 봐야 합니다. 클라이언트 제어는 UX 보조일 뿐 최종 방어선은 서버입니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>프론트에서 막으면 충분한가요?</td><td>아닙니다. 공격자는 API를 직접 호출할 수 있으므로 서버 검증이 필요합니다.</td></tr><tr><td>보안과 UX가 충돌하면?</td><td>위험도와 자산 중요도를 기준으로 단계적 인증, 세션 정책, 로깅을 설계합니다.</td></tr><tr><td>검증 증거는?</td><td>negative test, audit log, penetration test, dependency scan, alert를 말합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“암호화합니다”, “토큰을 씁니다”처럼 방어 이름만 말하면 약합니다. 무엇을 누구로부터 보호하는지 먼저 말해야 합니다.</p></div>\n</section>\n\n<section id=\"security-q2\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-02</span><h2>Q. Threat Modeling은 어떻게 하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>Threat Modeling은 기능을 만들기 전에 공격자가 어떤 경로로 어떤 자산을 해칠 수 있는지 구조적으로 보는 활동입니다. OWASP Top 10은 이 위협을 코드 리뷰와 테스트 체크리스트로 구체화할 때 유용한 기준입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Threat Modeling은 완벽한 공격 목록을 만드는 행사가 아니라 설계 단계에서 신뢰 경계를 눈에 보이게 만드는 작업입니다. 데이터 흐름을 그리고 외부 입력, 권한 상승, 민감정보 저장, 외부 호출 지점을 찾습니다. STRIDE 같은 프레임은 누락을 줄이는 체크리스트이지 목적 자체가 아닙니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">먼저 자산, 사용자 역할, 데이터 흐름, 신뢰 경계를 그립니다. 그 다음 각 경계에서 조작 가능한 입력, 권한 상승, 데이터 유출, 위조, 재전송, 서비스 거부 가능성을 봅니다. 위험도에 따라 서버 검증, 권한 모델, 암호화, rate limit, 로그, 알림을 설계합니다.</div>\n<h3>90초 답변</h3>\n<p>예를 들어 multi-tenant 관리자 화면에서는 tenant A 사용자가 tenant B 데이터를 볼 수 있는지, URL id를 바꾸면 접근되는지, export 기능이 과도한 데이터를 내보내는지, audit log가 충분한지 봅니다. STRIDE 같은 프레임은 Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege로 위협을 빠짐없이 보는 데 도움을 줍니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>언제 해야 하나요?</td><td>권한, 결제, 개인정보, 외부 callback, 파일 처리처럼 위험한 기능 설계 시점에 합니다.</td></tr><tr><td>모든 기능에 하나요?</td><td>위험도 기반으로 깊이를 조절하고 checklist를 코드 리뷰에 반영합니다.</td></tr><tr><td>산출물은?</td><td>데이터 흐름, 신뢰 경계, 위협 목록, 완화책, 잔여 위험, 테스트 케이스입니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>권한 기능, 파일 업로드, OAuth callback, webhook 같은 기능에서 threat model을 적용한 예를 준비합니다.</p>\n</section>\n\n<section id=\"security-q3\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-03</span><h2>Q. IDOR와 접근 제어 취약점은 어떻게 막나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>IDOR는 사용자가 식별자를 바꿔 다른 사용자의 리소스에 접근하는 취약점입니다. 방어는 id를 숨기는 것이 아니라 서버가 actor, action, resource 관계를 검증하는 것입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>IDOR는 사용자가 인증됐다는 사실과 특정 객체에 접근할 권한이 있다는 사실을 혼동할 때 생깁니다. URL이나 body의 id를 신뢰하지 말고 서버에서 actor, resource, action 관계를 확인해야 합니다. tenant id 누락은 B2B SaaS에서 가장 치명적인 접근 제어 실수 중 하나입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">IDOR는 URL이나 body의 id를 바꿨을 때 권한 검증 없이 다른 리소스가 노출될 때 생깁니다. UUID를 쓰거나 버튼을 숨기는 것으로는 충분하지 않습니다. 모든 API에서 현재 사용자, 역할, tenant, resource owner, action 권한을 서버에서 검증해야 합니다.</div>\n<h3>90초 답변</h3>\n<p>접근 제어는 인증 후 한 번만 하는 것이 아니라 리소스마다 해야 합니다. 관리자 화면에서는 role만 보면 부족하고 organization, tenant, project, data scope를 함께 확인해야 합니다. 목록 API와 상세 API, export API, bulk action, 파일 다운로드 API 모두 같은 권한 모델을 적용해야 합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>UUID면 안전한가요?</td><td>추측은 어려워도 권한 검증이 없으면 유출된 URL로 접근 가능합니다.</td></tr><tr><td>테스트는?</td><td>다른 사용자/tenant의 id로 negative test를 작성합니다.</td></tr><tr><td>캐시와 권한은?</td><td>사용자별/tenant별 cache key를 분리하고 민감 응답은 public cache하지 않습니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“프론트에서 메뉴를 숨겼습니다”는 접근 제어가 아닙니다.</p></div>\n</section>\n\n<section id=\"security-q4\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-04</span><h2>Q. 인증과 세션 관리는 어떻게 설계하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>인증은 사용자가 누구인지 확인하는 것이고, 세션 관리는 그 인증 상태를 안전하게 유지하고 종료하는 체계입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>세션 관리는 로그인 순간보다 로그인 이후의 수명 관리가 더 중요합니다. 세션 만료, rotation, revoke, device 관리, CSRF/XSS 위협, refresh token 재사용 탐지가 모두 포함됩니다. 인증 정보가 유출됐을 때 피해를 줄이는 설계가 안전한 세션 설계입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">세션은 발급, 저장, 만료, 갱신, 폐기, 탈취 대응을 함께 설계해야 합니다. Cookie를 쓴다면 HttpOnly, Secure, SameSite, CSRF 방어를 보고, server-side session이면 session store, device revoke, idle timeout, absolute timeout을 봅니다.</div>\n<h3>90초 답변</h3>\n<p>세션 fixation을 막으려면 로그인 성공 시 session id를 재발급해야 합니다. 로그아웃은 클라이언트 토큰 삭제뿐 아니라 server-side session invalidate나 refresh token revoke가 필요합니다. 민감 작업에는 step-up authentication이나 재인증을 적용할 수 있습니다. 여러 기기 로그인, 비밀번호 변경 후 세션 폐기 정책도 중요합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>session fixation은?</td><td>공격자가 정한 session id로 피해자가 로그인하게 하는 공격이며 로그인 시 재발급합니다.</td></tr><tr><td>remember me는?</td><td>장기 토큰 저장과 rotation, device revoke, 탈취 탐지를 설계해야 합니다.</td></tr><tr><td>로그아웃은?</td><td>클라이언트 삭제와 서버 revoke/invalidate를 함께 봅니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>세션 만료 정책, cookie flag, refresh token revoke, device 관리 경험을 말합니다.</p>\n</section>\n\n<section id=\"security-q5\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-05</span><h2>Q. OAuth2와 OIDC는 어떻게 다르나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>OAuth2는 권한 위임 프레임워크이고, OIDC는 OAuth2 위에 identity layer를 얹어 로그인과 사용자 정보를 표준화한 프로토콜입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>OAuth2는 권한 위임 프레임워크이고, OIDC는 그 위에 identity layer를 얹어 사용자가 누구인지 확인하게 해줍니다. access token은 API 접근 권한을 나타내고, id token은 client가 사용자의 인증 정보를 확인하기 위한 token입니다. redirect URI, state, PKCE, nonce를 혼동하면 공격 표면이 커집니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">OAuth2의 access token은 API 접근 권한을 나타내고, OIDC의 id token은 사용자가 누구인지에 대한 인증 정보를 담습니다. 로그인에는 authorization code flow와 PKCE를 사용하고, redirect URI, state, nonce, token audience, scope 검증이 중요합니다.</div>\n<h3>90초 답변</h3>\n<p>보안상 implicit flow보다 authorization code + PKCE가 권장됩니다. state는 CSRF 방어, nonce는 id token replay 방어에 사용됩니다. redirect URI를 넓게 허용하면 authorization code 탈취 위험이 있고, id token을 API authorization에 쓰면 audience와 목적이 맞지 않을 수 있습니다. refresh token rotation과 reuse detection은 장기 토큰 탈취를 탐지하고 피해를 줄이는 핵심 방어선입니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>PKCE는 왜 필요한가요?</td><td>authorization code를 탈취해도 code verifier 없이는 token 교환을 못 하게 합니다.</td></tr><tr><td>state와 nonce 차이는?</td><td>state는 요청 위조 방어, nonce는 id token replay 방어입니다.</td></tr><tr><td>refresh token은?</td><td>장기 권한이므로 rotation, reuse detection, revoke가 필요합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>OAuth를 “소셜 로그인”으로만 말하면 부족합니다. 권한 위임과 identity layer를 구분하세요.</p></div>\n</section>\n\n<section id=\"security-q6\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-06</span><h2>Q. JWT는 어떻게 검증해야 안전한가요?</h2></div>\n<h3>핵심 개념</h3>\n<p>JWT는 서명된 claim 묶음이며, 안전하려면 서명뿐 아니라 issuer, audience, expiry, algorithm, key rotation, revoke 전략을 함께 검증해야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>JWT 검증은 서명만 확인하는 것으로 끝나지 않습니다. issuer, audience, expiration, not-before, algorithm, key id, clock skew, token type을 모두 검증해야 합니다. claim은 사용자가 바꿀 수 없도록 서명되어 있지만, 서버가 그 claim을 어떤 권한으로 해석할지는 별도 정책입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">JWT는 header, payload, signature로 구성됩니다. 서버는 signature를 검증하고 exp, nbf, iss, aud, scope를 확인해야 합니다. algorithm confusion을 막기 위해 허용 algorithm을 고정하고, key rotation과 JWKS cache, clock skew도 고려합니다.</div>\n<h3>90초 답변</h3>\n<p>JWT의 장점은 stateless 검증이지만 즉시 revoke가 어렵다는 단점이 있습니다. 그래서 access token은 짧게 유지하고 refresh token은 server-side 저장과 rotation을 둡니다. 민감 권한 변경이나 계정 차단 시에는 token version, denylist, introspection 같은 보완책을 검토합니다. payload는 암호화가 아니므로 민감정보를 넣지 않습니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>JWT를 localStorage에 저장하면?</td><td>XSS에 취약하므로 threat model을 보고 HttpOnly cookie 등 대안을 검토합니다.</td></tr><tr><td>audience 검증은 왜?</td><td>다른 API용 토큰이 우리 API에서 재사용되는 것을 막습니다.</td></tr><tr><td>서명만 맞으면 되나요?</td><td>아닙니다. 만료, 발급자, 대상, 권한, algorithm까지 검증해야 합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>JWT 검증 middleware에서 checked claim 목록과 실패 로그를 설명하면 좋습니다.</p>\n</section>\n\n<section id=\"security-q7\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-07</span><h2>Q. XSS와 CSRF는 어떻게 다르고 어떻게 막나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>XSS는 공격자 입력이 브라우저에서 스크립트로 실행되는 문제이고, CSRF는 사용자의 인증 상태를 이용해 원치 않는 요청을 보내는 문제입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>XSS는 공격자가 우리 origin에서 JavaScript를 실행하게 만드는 문제이고, CSRF는 사용자의 인증 상태를 이용해 원치 않는 요청을 보내게 하는 문제입니다. XSS 방어는 context-aware escaping, sanitization, CSP가 중심이고, CSRF 방어는 SameSite, CSRF token, origin 검증이 중심입니다. 둘은 원인과 방어선이 다릅니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">XSS는 output escaping, sanitization, CSP, dangerous HTML 제한으로 막고, CSRF는 SameSite cookie, CSRF token, Origin/Referer 검증으로 막습니다. XSS는 토큰 탈취와 사용자 대신 행동을 가능하게 하므로 CSRF 방어만으로는 부족합니다.</div>\n<h3>90초 답변</h3>\n<p>React는 기본적으로 문자열을 escape하지만 dangerouslySetInnerHTML, markdown/html rendering, third-party widget, URL injection에서는 위험이 남습니다. CSRF는 cookie 기반 인증에서 특히 중요합니다. JSON API라도 preflight가 항상 보안 장벽은 아니며 state-changing 요청은 서버에서 origin과 token을 검증해야 합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>CSP는 만능인가요?</td><td>피해를 줄이는 방어선이지만 escaping과 sanitization을 대체하지 않습니다.</td></tr><tr><td>SameSite=Lax면 충분한가요?</td><td>요구사항과 browser 동작을 보고 민감 요청에는 token 검증도 고려합니다.</td></tr><tr><td>stored XSS와 reflected XSS는?</td><td>저장된 입력이 나중에 실행되는지, 요청에 반사되어 실행되는지 차이입니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“React라 XSS가 없습니다”는 틀린 답변입니다. HTML 삽입과 URL, 외부 콘텐츠를 봐야 합니다.</p></div>\n</section>\n\n<section id=\"security-q8\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-08</span><h2>Q. SQL Injection과 Command Injection은 어떻게 막나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>Injection은 사용자 입력이 명령이나 쿼리의 데이터가 아니라 구조로 해석될 때 발생합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Injection은 신뢰할 수 없는 입력이 명령이나 쿼리의 구조로 해석될 때 생깁니다. SQL은 parameterized query로 값과 쿼리 구조를 분리하고, command execution은 가능하면 shell 호출 자체를 피해야 합니다. allowlist validation은 입력 공간을 좁히는 보조 방어선입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">SQL Injection은 prepared statement와 parameter binding으로 막고, 동적 order by나 column name처럼 바인딩할 수 없는 부분은 allowlist를 씁니다. Command Injection은 shell 문자열 조합을 피하고, 인자 배열 API와 allowlist validation, 권한 제한, sandbox를 사용합니다.</div>\n<h3>90초 답변</h3>\n<p>ORM을 쓴다고 injection이 자동으로 사라지는 것은 아닙니다. raw query, string interpolation, 동적 검색 조건, report query에서 위험이 남습니다. 입력 검증은 보조 방어선이고 핵심은 코드와 데이터를 분리하는 것입니다. 에러 메시지에 SQL이나 내부 경로를 노출하지 않는 것도 중요합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>LIKE 검색은?</td><td>parameter binding과 wildcard escape를 함께 봅니다.</td></tr><tr><td>동적 정렬은?</td><td>사용자 입력을 column allowlist에 매핑합니다.</td></tr><tr><td>파일 변환 명령은?</td><td>shell=false, 인자 배열, 파일명 검증, 임시 디렉터리 격리를 씁니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>raw query 리뷰, allowlist validation, negative test, scanner 결과 대응 경험을 말합니다.</p>\n</section>\n\n<section id=\"security-q9\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-09</span><h2>Q. SSRF는 왜 위험하고 어떻게 방어하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>SSRF는 서버가 공격자가 지정한 URL로 요청을 보내게 되어 내부망, metadata endpoint, admin service에 접근할 수 있는 취약점입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>SSRF는 서버가 내부망이나 metadata endpoint에 접근할 수 있다는 점을 공격자가 악용하는 취약점입니다. URL allowlist, DNS rebinding 방어, private IP 차단, egress policy, metadata service 보호가 필요합니다. 단순히 client에서 URL 형식을 검사하는 것으로는 부족합니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">SSRF는 URL fetch, webhook test, image import, PDF generation 같은 기능에서 생길 수 있습니다. 방어는 URL allowlist, private IP/link-local 차단, DNS rebinding 대응, redirect 제한, timeout, response size 제한, metadata endpoint 차단입니다.</div>\n<h3>90초 답변</h3>\n<p>단순히 문자열이 http로 시작하는지만 보면 우회됩니다. DNS 해석 결과가 private IP인지 확인하고, redirect 후 최종 주소도 검사해야 합니다. IPv6, decimal/hex IP, localhost alias, internal DNS 이름도 고려합니다. 가능하면 외부 fetch는 별도 egress 제한 환경에서 수행하고, 접근 가능한 네트워크를 최소화합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>metadata endpoint가 왜 위험한가요?</td><td>클라우드 credential이나 instance metadata가 유출될 수 있습니다.</td></tr><tr><td>allowlist와 blocklist 중?</td><td>가능하면 allowlist가 안전하고 blocklist는 우회가 많습니다.</td></tr><tr><td>redirect는?</td><td>초기 URL뿐 아니라 redirect 최종 URL도 검증해야 합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>SSRF는 “외부 URL 호출” 기능 전체의 egress 통제 문제로 봐야 합니다.</p></div>\n</section>\n\n<section id=\"security-q10\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-10</span><h2>Q. 비밀번호와 Secret은 어떻게 저장하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>비밀번호는 복호화 가능한 암호화가 아니라 password hashing으로 저장하고, secret은 저장·주입·회전·감사 체계를 갖춰야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>비밀번호는 복호화할 필요가 없는 secret이므로 느린 password hashing 함수와 salt로 저장해야 합니다. API key나 OAuth secret처럼 다시 사용해야 하는 secret은 암호화, 접근 제어, rotation, audit가 필요합니다. Secret은 코드, 로그, error report, analytics로 새어나가지 않게 경로를 점검해야 합니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">비밀번호는 bcrypt, scrypt, Argon2 같은 password hashing을 사용하고 salt와 work factor를 둡니다. secret은 코드와 이미지에 넣지 않고 secret manager에서 관리하며, 접근 권한, rotation, 로그 마스킹, 유출 시 revoke 절차를 마련합니다.</div>\n<h3>90초 답변</h3>\n<p>비밀번호 reset token은 충분히 랜덤해야 하고 짧은 만료와 1회 사용 정책이 필요합니다. 로그인과 reset, OTP endpoint에는 rate limit과 abuse detection이 필요합니다. secret rotation은 새 secret과 구 secret이 잠시 공존할 수 있는지, 배포 순서가 안전한지까지 봐야 합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>암호화와 hashing 차이는?</td><td>암호화는 복호화 가능, password hashing은 검증만 가능하도록 설계합니다.</td></tr><tr><td>pepper는?</td><td>DB와 별도 저장소에 둔 추가 secret으로 hash 방어를 보강할 수 있습니다.</td></tr><tr><td>secret 유출 시?</td><td>revoke/rotate, 로그 확인, 영향 범위 산정, 재발 방지를 수행합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>secret scan, rotation runbook, log redaction, password reset abuse 방어를 말하면 좋습니다.</p>\n</section>\n\n<section id=\"security-q11\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-11</span><h2>Q. Multi-tenant SaaS에서 보안상 가장 중요한 것은 무엇인가요?</h2></div>\n<h3>핵심 개념</h3>\n<p>Multi-tenant 보안의 핵심은 tenant isolation입니다. 한 고객의 사용자나 관리자가 다른 고객의 데이터에 접근하지 못해야 합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Multi-tenant 보안의 핵심은 모든 데이터 접근 경로에 tenant boundary가 빠지지 않게 하는 것입니다. UI 메뉴, API query, background job, export, search index, cache key까지 tenant 조건이 들어가야 합니다. 한 곳의 누락이 다른 고객 데이터 노출로 이어질 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">모든 query와 API에서 tenant scope를 강제해야 합니다. URL id, filter, export, background job, cache key, search index, object storage path, audit log까지 tenant_id가 누락되지 않게 설계합니다. 권한 검증은 role뿐 아니라 tenant membership과 resource scope를 함께 봐야 합니다.</div>\n<h3>90초 답변</h3>\n<p>tenant isolation은 코드 리뷰만으로 보장하기 어렵습니다. repository layer에서 tenant filter를 기본 적용하거나 row-level security, scoped service API, integration test를 둡니다. cache key에 tenant가 빠지거나 object storage prefix 권한이 넓으면 DB 권한이 맞아도 데이터가 샐 수 있습니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>admin은 모든 tenant를 볼 수 있나요?</td><td>운영자 권한도 승인, 감사, 최소 권한, break-glass 절차가 필요합니다.</td></tr><tr><td>batch job은?</td><td>tenant별 범위와 실패 격리, audit log를 남겨야 합니다.</td></tr><tr><td>검색 인덱스는?</td><td>tenant filter가 index query에도 강제되어야 합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>tenant_id를 “프론트에서 넘겨준다”는 설계는 위험합니다. 서버가 세션과 권한에서 scope를 결정해야 합니다.</p></div>\n</section>\n\n<section id=\"security-q12\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-12</span><h2>Q. 감사 로그는 일반 로그와 어떻게 다르나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>감사 로그는 디버깅 로그가 아니라 누가, 언제, 어떤 권한으로, 어떤 대상에, 어떤 변경을 했는지 추적하는 보안 증거입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>감사 로그는 디버깅 로그가 아니라 나중에 누가 어떤 민감한 행동을 했는지 증명하는 기록입니다. actor, target, action, result, reason, before/after, request id, timestamp가 중요하고 임의 수정이 어려워야 합니다. 개인정보와 secret을 과하게 남기면 감사 로그 자체가 위험 자산이 됩니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">audit log에는 actor, action, target, tenant, result, reason, source IP, user agent, traceId, before/after summary를 남깁니다. 민감정보 원문은 남기지 않고 마스킹하며, 변경 불가능성, 보관 기간, 접근 권한도 관리해야 합니다.</div>\n<h3>90초 답변</h3>\n<p>감사 로그는 사고 대응과 고객 문의, 규제 대응에 필요합니다. 예를 들어 관리자가 권한을 바꾸거나 파일을 export하거나 결제 상태를 수정한 경우 누가 왜 했는지 확인할 수 있어야 합니다. 로그가 너무 많아도 찾기 어려우므로 중요 action을 정의하고 검색 가능한 구조로 남깁니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>민감정보는?</td><td>원문 저장을 피하고 tokenization/masking/redaction을 적용합니다.</td></tr><tr><td>위변조 방지는?</td><td>append-only 저장, 권한 제한, 별도 계정, checksum 또는 외부 로그 저장을 봅니다.</td></tr><tr><td>alert는?</td><td>권한 변경, 대량 export, 실패한 로그인, 비정상 지역 접근 같은 이벤트를 봅니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3>\n<p>운영자 action, 권한 변경, 데이터 export에 audit log를 설계한 경험을 말합니다.</p>\n</section>\n\n<section id=\"security-q13\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-13</span><h2>Q. 보안 사고가 발생하면 어떤 순서로 대응하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>보안 사고 대응은 탐지, 격리, 영향 범위 산정, 증거 보존, 근절, 복구, 고지, 재발 방지의 순서로 진행합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>보안 사고 대응은 원인 분석보다 격리와 증거 보존이 먼저입니다. 영향 범위, 공격 경로, 노출 데이터, credential rotation, 임시 차단, 법적/고객 공지 기준을 순서대로 봐야 합니다. 로그를 지우거나 시스템을 성급히 재배포하면 포렌식 단서가 사라질 수 있습니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">먼저 사고인지 확인하고 영향 범위를 좁힙니다. 유출된 token이나 secret은 revoke/rotate하고, 취약 endpoint나 계정을 격리합니다. 로그와 증거를 보존한 뒤 패치, 복구, 사용자 고지 판단, postmortem과 재발 방지 action을 진행합니다.</div>\n<h3>90초 답변</h3>\n<p>사고 대응에서는 원인 분석보다 확산 방지가 먼저일 수 있습니다. 예를 들어 access key 유출이면 즉시 비활성화하고 어떤 리소스에 접근했는지 audit log를 봅니다. 개인정보 가능성이 있으면 법무/보안/운영 커뮤니케이션 경로를 따르고, 임의로 로그를 지우면 증거가 사라질 수 있습니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>secret 유출이면?</td><td>rotate/revoke, 접근 로그 확인, downstream credential 재발급, scan rule 추가를 말합니다.</td></tr><tr><td>사용자 고지는?</td><td>영향 데이터, 법적 요구, 회사 프로세스에 따라 판단합니다.</td></tr><tr><td>postmortem에는?</td><td>timeline, detection gap, blast radius, root cause, action owner와 due date를 남깁니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“패치하면 끝”이 아닙니다. 영향 범위, 증거, 고지, 재발 방지까지 사고 대응입니다.</p></div>\n</section>\n\n<section id=\"security-q14\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-14</span><h2>핵심 질문 40선과 답변 훈련</h2></div>\n<p class=\"lede\">보안 심화 면접은 방어 기술명을 외우는 것보다 공격 경로와 서버 방어선을 끝까지 추적하는 훈련입니다.</p>\n<table>\n<tr><th>축</th><th>핵심 질문</th><th>확장 포인트</th></tr>\n<tr><td>모델링</td><td>자산, 신뢰 경계, STRIDE, OWASP, abuse case</td><td>공격자가 조작 가능한 입력 찾기</td></tr>\n<tr><td>권한</td><td>IDOR, RBAC, ABAC, tenant isolation, admin access, audit</td><td>actor/action/resource/scope 검증</td></tr>\n<tr><td>인증</td><td>session, cookie, OAuth2, OIDC, JWT, refresh token, logout</td><td>발급, 저장, 검증, revoke, rotation</td></tr>\n<tr><td>웹 취약점</td><td>XSS, CSRF, SQLi, command injection, SSRF, file upload</td><td>서버 방어와 우회 가능성</td></tr>\n<tr><td>운영</td><td>secret, rate limit, dependency scan, log redaction, incident response</td><td>탐지와 복구 체계</td></tr>\n</table>\n<h3>구체 질문 12선</h3>\n<table>\n<tr><th>번호</th><th>구체 질문</th><th>답변 방향</th></tr>\n<tr><td>1</td><td>사용자가 URL을 입력하는 이미지 가져오기 기능에서 SSRF를 어떻게 negative test하나요?</td><td>localhost, link-local, private IP, redirect, DNS rebinding, IPv6 우회를 넣고 차단 로그를 확인합니다.</td></tr>\n<tr><td>2</td><td>OAuth callback에서 state가 빠졌을 때 공격자는 어떤 체인을 만들 수 있나요?</td><td>CSRF로 victim session에 attacker authorization code를 연결하는 login CSRF를 설명합니다.</td></tr>\n<tr><td>3</td><td>OIDC nonce는 state와 다르게 어떤 공격을 줄이나요?</td><td>id token replay와 요청-응답 바인딩 실패를 줄이며 state는 CSRF 방어임을 구분합니다.</td></tr>\n<tr><td>4</td><td>PKCE가 있으면 client secret이 없는 public client에서 무엇을 보호하나요?</td><td>authorization code 탈취 후 token 교환을 code verifier 없이는 실패하게 합니다.</td></tr>\n<tr><td>5</td><td>JWT alg confusion은 어떤 검증 실수에서 생기나요?</td><td>허용 algorithm을 고정하지 않거나 header alg를 그대로 신뢰할 때 생깁니다.</td></tr>\n<tr><td>6</td><td>JWT key confusion은 JWKS나 kid 처리에서 어떻게 발생하나요?</td><td>issuer별 key set 분리 실패, kid만 믿는 key 선택, 임의 JWKS URL 신뢰를 봅니다.</td></tr>\n<tr><td>7</td><td>tenant cache key에 tenant_id가 빠지면 DB 권한 검증이 맞아도 왜 유출이 생기나요?</td><td>첫 tenant의 응답이 공유 cache key로 다른 tenant에 재사용되는 경로를 설명합니다.</td></tr>\n<tr><td>8</td><td>IDOR 테스트는 상세 API만 보면 충분하지 않은 이유는 무엇인가요?</td><td>목록, export, bulk action, search, file download, background job까지 접근 경로가 다릅니다.</td></tr>\n<tr><td>9</td><td>보안 로그에서 blocked 이벤트만 보면 부족한 이유는 무엇인가요?</td><td>성공 이벤트, 실패율, actor/tenant/source IP, traceId, 탐지 누락을 함께 봐야 합니다.</td></tr>\n<tr><td>10</td><td>React 앱에서도 XSS가 생기는 대표 sink는 무엇인가요?</td><td>dangerouslySetInnerHTML, markdown HTML, URL scheme injection, third-party script를 봅니다.</td></tr>\n<tr><td>11</td><td>refresh token rotation에서 reuse detection이 필요한 이유는 무엇인가요?</td><td>탈취된 구 token 재사용을 침해 신호로 보고 session family를 revoke하기 위해서입니다.</td></tr>\n<tr><td>12</td><td>incident postmortem에서 detection gap을 어떻게 설명해야 하나요?</td><td>공격 시점, 최초 탐지, alert 부재, 로그 필드 부족, 새 탐지 룰을 시간순으로 정리합니다.</td></tr>\n</table>\n<div class=\"callout risk\"><span class=\"co-label\">압박 꼬리질문</span><p>“UUID면 IDOR가 막히나요?”, “JWT 서명만 검증하면 되나요?”, “React라 XSS가 없나요?”, “private URL fetch 기능에서 SSRF를 어떻게 막나요?”, “tenant_id를 프론트에서 넘기면 왜 위험하죠?”에 답할 수 있어야 합니다.</p></div>\n</section>\n\n<section id=\"security-q15\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-15</span><h2>공격 경로 기반 답변</h2></div>\n<p class=\"lede\">보안 면접에서 전문성은 방어 기술명을 나열하는 데서 나오지 않습니다. 공격자가 어디서 들어와 어떤 권한 경계를 넘어 어떤 sink에 도달하는지 추적해야 합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SECURITY ATTACK PATH ANSWER</span>\n답변은 source, trust boundary, authorization check, sink, impact, detection, mitigation 순서로 구성합니다. 예를 들어 SSRF는 사용자가 조작한 URL(source)이 서버 내부 네트워크 경계(boundary)를 넘어 metadata endpoint나 internal admin API(sink)에 닿는 문제입니다. 방어는 allowlist, DNS/IP 재검증, private range 차단, redirect 제한, egress policy, timeout, response filtering, audit log를 조합합니다.\n</div>\n<table>\n<tr><th>취약점</th><th>공격 경로로 설명할 핵심</th><th>방어선</th></tr>\n<tr><td>IDOR</td><td>사용자가 resource id를 바꿔 다른 tenant/user 자원에 접근합니다.</td><td>actor-action-resource-scope 검증, tenant boundary, 서버 권한 체크, 감사 로그</td></tr>\n<tr><td>XSS</td><td>untrusted input이 HTML/JS sink로 들어가 사용자 브라우저에서 실행됩니다.</td><td>context-aware escaping, CSP, sanitization, HttpOnly cookie, 위험 sink 금지</td></tr>\n<tr><td>CSRF</td><td>인증 cookie가 자동 전송되는 특성을 이용해 사용자의 의도 없는 state change를 만듭니다.</td><td>SameSite, CSRF token, origin 검증, idempotent GET 원칙</td></tr>\n<tr><td>Injection</td><td>입력이 query/command/template 문법으로 해석됩니다.</td><td>parameter binding, allowlist, least privilege, output validation, error masking</td></tr>\n<tr><td>JWT 오용</td><td>토큰 저장·검증·폐기 경계가 약해 탈취나 권한 상승으로 이어집니다.</td><td>issuer/audience/expiry 검증, key rotation, refresh token 보호, revoke 전략</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">면접 주의</span>\n<p>“프론트에서 막았습니다”, “UUID라 어렵습니다”, “JWT라 stateless입니다” 같은 답변은 보안 경계가 서버에 있다는 점을 놓칩니다. 방어는 우회 가능성을 전제로 서버 권한 검증과 운영 탐지를 포함해야 합니다.</p>\n</div>\n</section>\n\n<section id=\"security-q16\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-16</span><h2>EXPLOIT CHAIN VALIDATION</h2></div>\n<p class=\"lede\">보안 심화 답변은 취약점 하나를 고립해서 말하지 않고, 공격자가 여러 약점을 연결해 실제 영향에 도달하는지 검증하는 방식으로 구성해야 합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">EXPLOIT CHAIN VALIDATION</span>\n검증 순서는 source, trust boundary, bypass, sink, impact, negative tests/detection logs입니다. SSRF DNS rebinding, OAuth state/nonce/PKCE 누락, JWT alg/key confusion, tenant cache key leak처럼 단일 실수보다 체인으로 이어질 때 실제 사고가 됩니다. 방어가 있다고 말하는 것보다 우회 입력이 차단되고 탐지 로그가 남는지 보여줘야 합니다.\n</div>\n<h3>대표 체인</h3>\n<table>\n<tr><th>체인</th><th>공격 흐름</th><th>검증해야 할 방어</th></tr>\n<tr><td>SSRF DNS rebinding</td><td>처음 DNS 해석은 허용 IP로 통과하고, 실제 연결 시 private IP나 metadata endpoint로 바뀝니다.</td><td>연결 직전 DNS/IP 재검증, private/link-local 차단, redirect 후 재검증, egress policy, 차단 로그</td></tr>\n<tr><td>OAuth/OIDC callback</td><td>state 누락은 login CSRF, nonce 누락은 id token replay, PKCE 누락은 code 탈취 후 token 교환으로 이어집니다.</td><td>state 세션 바인딩, nonce 검증, PKCE verifier 검증, redirect URI exact match, 실패 이벤트 로깅</td></tr>\n<tr><td>JWT alg/key confusion</td><td>header의 alg/kid를 과신하거나 issuer별 key를 분리하지 않아 공격자 token이 정상 검증됩니다.</td><td>허용 alg 고정, issuer/audience별 JWKS 분리, kid miss 실패 처리, none/HS-RS 혼동 negative test</td></tr>\n<tr><td>Tenant cache key leak</td><td>DB query는 tenant filter가 맞지만 cache key가 resource id만 써서 다른 tenant 응답이 재사용됩니다.</td><td>tenant/user/scope를 포함한 cache key, 민감 응답 no-store, cross-tenant negative test, cache hit 로그</td></tr>\n</table>\n<h3>Negative Tests와 Detection Logs</h3>\n<p>negative tests는 “정상 요청이 된다”가 아니라 “공격 입력이 실패하고 실패 이유가 관측된다”를 검증합니다. SSRF는 <code>127.0.0.1</code>, <code>169.254.169.254</code>, IPv6 loopback, decimal/hex IP, redirect, DNS rebinding 도메인을 넣고 차단 결과를 봅니다. OAuth는 state mismatch, nonce mismatch, PKCE verifier mismatch, redirect URI 변조를 넣습니다. JWT는 허용되지 않은 alg, 다른 issuer의 kid, 잘못된 audience, 만료 token, 서명 key 혼동을 테스트합니다. multi-tenant는 tenant A 세션으로 tenant B cache hit가 발생하지 않는지 확인합니다.</p>\n<p>detection logs에는 actor, tenant, source IP, user agent, request id, blocked reason, normalized target, token issuer/audience, cache key scope, decision을 남깁니다. 민감 원문 token이나 secret은 남기지 않습니다. 면접에서는 “막았습니다”보다 “어떤 우회 입력이 어떤 로그와 alert로 실패하는지”를 말해야 합니다.</p>\n<div class=\"callout risk\"><span class=\"co-label\">검증 기준</span><p>방어가 코드에 존재해도 체인의 다음 단계가 남아 있으면 취약합니다. 예를 들어 SSRF URL allowlist가 있어도 redirect 최종 URL과 DNS rebinding을 재검증하지 않으면 내부망 sink에 도달할 수 있습니다.</p></div>\n</section>\n\n<section id=\"security-q17\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEC-17</span><h2>보안 개념 인과관계</h2></div>\n<p class=\"lede\">보안 답변은 취약점 이름을 맞히는 것이 아니라 공격자가 신뢰 경계를 어떻게 넘고, 어떤 sink에 도달하며, 어떤 통제로 그 경로를 끊는지 설명해야 깊어집니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">SECURITY CAUSAL MODEL</span>취약점은 보통 “사용자 입력이 있다”만으로 생기지 않습니다. 입력이 신뢰 경계를 넘어 정규화되지 않은 채 권한 판단, URL fetch, SQL, HTML sink, file path, cache key 같은 민감한 지점에 도달할 때 문제가 됩니다. XSS는 untrusted string이 DOM execution sink에 들어가서 발생하고, IDOR는 resource id를 바꿨을 때 서버가 actor-resource 관계를 검증하지 않아 발생합니다. SSRF는 서버가 대신 네트워크 요청을 보내기 때문에 내부망 접근 권한이 공격자에게 빌려지는 구조입니다. 그래서 방어는 입력 검증 하나가 아니라 normalize, authorize, constrain, log, alert를 경로마다 둬야 합니다.</div>\n<table>\n<tr><th>취약점</th><th>원인</th><th>공격 결과</th><th>방어 논리</th></tr>\n<tr><td>IDOR</td><td>resource id는 바꿀 수 있는데 actor-resource 권한 검증이 없다</td><td>다른 사용자나 tenant 데이터 조회·수정</td><td>서버에서 owner/tenant/scope를 매 요청 검증하고 negative test를 둔다</td></tr>\n<tr><td>XSS</td><td>untrusted input이 escaping 없이 HTML/JS sink로 들어간다</td><td>세션 탈취, 임의 요청, 화면 변조</td><td>context-aware escaping, sanitization, CSP, Trusted Types를 조합한다</td></tr>\n<tr><td>SSRF</td><td>서버가 공격자가 준 URL로 내부 네트워크 요청을 보낸다</td><td>metadata 탈취, 내부 admin endpoint 접근</td><td>scheme/host/IP/redirect 재검증, private range 차단, egress policy를 둔다</td></tr>\n<tr><td>JWT 혼동</td><td>issuer, audience, alg, kid 검증이 약하다</td><td>다른 발급자 token이나 조작 token이 통과한다</td><td>허용 alg 고정, issuer별 key 분리, audience/scope 검증을 강제한다</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">암기 답변 교정</span>\n<p>“XSS는 script 삽입입니다”에서 멈추지 말고 “입력 위치에 따라 HTML, attribute, URL, JS context escaping이 다르고, React 기본 escaping으로 막히지 않는 dangerouslySetInnerHTML이나 third-party HTML renderer는 별도 sanitization이 필요합니다”까지 이어가야 합니다.</p>\n</div>\n</section>",
};

export default document;
